INSERT INTO `activity` VALUES (1, '字里千秋 —— 活字印刷术沉浸式体验日', '2025-05-30 09:00:00', '2025-08-10 10:00:00', 'http://localhost:9090/files/download/1747877975287-活字印刷、.jpg', '活字印刷术是中国古代 “四大发明” 之一，北宋匠人毕昇发明的泥活字标志着印刷术的革命性突破。本次活动以 “重现千年印刷智慧” 为主题，通过古法流程还原、匠人实操教学、现代创意延伸三大板块，让参与者亲手制作木活字、排版印刷古诗笺，在油墨与活字的碰撞中，感受汉字的形态之美与文化传承的温度。', '<p><span style=\"font-size: 16px;\"><strong>主办单位</strong></span>：非物质文化遗产协会<br><span style=\"font-size: 16px;\"><strong>活动地点</strong></span>：合肥市市博物馆非遗体验厅<br><span style=\"font-size: 16px;\"><strong>参与人数</strong></span>：30 人（需提前预约，限 10 岁以上观众）</p><h3 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>一、活动简介</strong></span></h3><p>活字印刷术是中国古代 “四大发明” 之一，北宋匠人毕昇发明的泥活字标志着印刷术的革命性突破。本次活动以 “重现千年印刷智慧” 为主题，通过<span style=\"font-size: 16px;\"><strong>古法流程还原、匠人实操教学、现代创意延伸</strong></span>三大板块，让参与者亲手制作木活字、排版印刷古诗笺，在油墨与活字的碰撞中，感受汉字的形态之美与文化传承的温度。<br><span style=\"font-size: 16px;\"><strong>亮点</strong></span>：<br></p><ul><li style=\"text-align: start;\">零距离接触国家级非遗项目 “木活字印刷技艺”；</li><li style=\"text-align: start;\">从制字、排版到印刷全流程体验，解锁 “印刷匠人” 身份；</li><li style=\"text-align: start;\">成品可定制姓名或诗句，带走独一无二的文化纪念品。</li></ul><h3 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>二、活动流程详解</strong></span></h3><h4 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>【开篇：文明的火种 —— 印刷术历史讲堂】</strong></span></h4><p><span style=\"font-size: 16px;\"><strong>时间</strong></span>：9:00-10:00<br><span style=\"font-size: 16px;\"><strong>地点</strong></span>：博物馆学术报告厅<br><span style=\"font-size: 16px;\"><strong>内容</strong></span>：<br></p><ol><li style=\"text-align: start;\">文物导览参观博物馆 “古代科技展厅”，重点讲解战国时期的印章、唐代雕版印刷品《金刚经》复制品，对比活字印刷与雕版印刷的效率差异。展示国家级非遗 “瑞安木活字” 实物：泛黄的字模箱、刻刀、鬃刷、松烟墨等工具，直观呈现匠人工艺。</li><li style=\"text-align: start;\">知识讲座主讲人：王建国（木活字印刷技艺省级传承人）主题：《从毕昇到当代：活字印刷的前世今生》核心内容：活字印刷术的发明背景与传播路径（如传入朝鲜、欧洲的影响）；木活字制作口诀 “横平竖直、撇捺舒展” 的力学原理；非遗保护现状：现代激光雕刻对传统刻字工艺的冲击与创新。<br></li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>互动环节</strong></span>：<br></li></ol><ul><li style=\"text-align: start;\">展示 “反刻字模”，邀请观众尝试认读（如 “福”“寿” 等字的反写形态），理解活字印刷 “正字反刻” 的原理。</li></ul><h4 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>【实操：匠人养成记 —— 活字印刷全流程体验】</strong></span></h4><p><span style=\"font-size: 16px;\"><strong>时间</strong></span>：10:30-13:00<br><span style=\"font-size: 16px;\"><strong>地点</strong></span>：非遗体验厅<br><span style=\"font-size: 16px;\"><strong>环节一：木活字雕刻工坊<br></strong></span></p><ul><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>材料准备</strong></span>：每人发放一块梨木字模坯（5cm×5cm）、微型刻刀、放大镜、铅笔。</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>教学步骤</strong></span>：<br></li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>成果</strong></span>：完成个人专属木活字，可刻字如 “张三印”“云水间”，字模底部用记号笔标注姓名以便区分。<br></li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>环节二：古法排版与印刷<br></strong></span></li><li style=\"text-align: start;\">工具介绍：字盘（竹制托盘）：用于排列活字；界行条（金属条）：分隔文字行间距；鬃刷（打刷）：蘸墨均匀涂抹活字表面；宣纸：选用安徽泾县手工宣纸，吸墨性佳。</li><li style=\"text-align: start;\">操作流程：排版：在字盘中按 “从右到左、从上到下” 的顺序排列活字，用界行条固定，确保版面平整；刷墨：用鬃刷蘸取松烟墨，轻拍活字表面 3-5 次，直至墨迹均匀；覆纸印刷：将宣纸对齐字盘，用干净的鬃刷轻扫纸面，揭起后即得正字印刷品。<br></li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>体验内容</strong></span>：<br></li><li style=\"text-align: start;\">基础版：印刷宋代诗人苏轼的《题西林壁》片段，感受古诗与活字的韵味结合；</li><li style=\"text-align: start;\">创意版：用自己刻的活字组合短句（如 “今日得闲”“心有繁花”），设计个性化书签或明信片。</li></ul><h4 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>【创新：当活字遇见现代 —— 跨界创作工作坊】</strong></span></h4><p><span style=\"font-size: 16px;\"><strong>时间</strong></span>：14:00-15:30<br><span style=\"font-size: 16px;\"><strong>地点</strong></span>：非遗体验厅<br><span style=\"font-size: 16px;\"><strong>内容</strong></span>：<br></p><ol><li style=\"text-align: start;\">活字 × 文创设计提供帆布袋、T 恤、环保袋等空白载体，学员用活字组合图案或文字，如：用 “梅”“兰”“竹”“菊” 活字印刷四君子图案；印上网络热词 “人间清醒”“烟火气”，感受传统工艺与现代语言的碰撞。</li><li style=\"text-align: start;\">数字赋能非遗用手机扫描活字印刷品上的二维码，观看 AR 动画：毕昇穿越到现代，讲解活字印刷的原理，或动态展示古代书坊的印刷场景。</li><li style=\"text-align: start;\">作品分享会每位参与者展示自己的活字刻字与印刷作品，分享创作思路（如为何选择该汉字、刻字过程中的困难）。传承人点评：从刻字刀法的流畅度、版面布局的美感、创意融合度三方面给予反馈，颁发 “小小印刷师” 证书。</li></ol><h4 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>【尾声：带走千年墨香 —— 活动收尾与延展】</strong></span></h4><p><span style=\"font-size: 16px;\"><strong>时间</strong></span>：15:30-16:30<br><span style=\"font-size: 16px;\"><strong>内容</strong></span>：<br></p><ol><li style=\"text-align: start;\">成果包装为每位学员的活字刻字作品定制木盒包装，内衬丝绸，附上手写卡片（注明刻字内容、活动日期）；印刷品装入博物馆定制信封，封口处加盖 “活字印刷体验” 纪念章。</li><li style=\"text-align: start;\">文化衍生品售卖现场展销木活字套装（含字模、印台、说明书）、活字纹样笔记本、《中国印刷史》绘本等，鼓励持续探索。</li><li style=\"text-align: start;\">反馈收集发放问卷：“你最感兴趣的环节”“希望后续增加的非遗体验”，为后续活动提供参考。合影留念：全体参与者手持作品与传承人在活字印刷场景复原装置前合影（背景为古代书坊布景，摆放雕版、线装书等道具）。</li></ol><h3 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>三、图片内容参考（文字描述）</strong></span></h3><h4 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>1. 活字雕刻现场</strong></span></h4><ul><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>画面主体</strong></span>：一位青少年低头专注刻字，左手按住梨木字模，右手握刻刀小心翼翼地雕琢笔画，木屑散落在操作台的牛皮垫上；</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>背景</strong></span>：传承人站在身后，手持放大镜观察学员动作，墙上挂着《汉字六书图解》海报，窗台摆放着晒干的梨木块（展示木活字原料）；</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>细节</strong></span>：学员面前的台灯散发暖光，照亮字模上的反写 “墨” 字，刻刀刀柄刻有 “守正” 二字（体现匠人精神）。</li></ul><h4 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>2. 古法印刷瞬间</strong></span></h4><ul><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>特写</strong></span>：宣纸覆盖在排好版的字盘上，一只手握着鬃刷轻轻扫过纸面，另一只手按住字盘边缘，阳光透过窗棂在纸面上投下活字的阴影；</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>中景</strong></span>：多个字盘整齐摆放在长桌上，每个字盘旁放着不同颜色的墨块（黑色、朱红色），参与者围坐桌边，神情专注地进行刷墨、覆纸动作；</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>背景</strong></span>：体验厅墙面装饰着古代印刷流程图（制字、排版、印刷、装订），墙角立着 “毕昇” 人偶模型，手持活字向观众 “讲解”。</li></ul><h4 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>3. 创意活字文创</strong></span></h4><ul><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>全景</strong></span>：展示台上陈列着各式作品 —— 印有 “山水之间” 的帆布包、用活字拼贴的星空主题 T 恤、刻有姓名的个性化藏书票；</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>特写</strong></span>：一张印刷在宣纸上的现代诗《活字说》，诗句 “横是江河竖是山，点捺之间皆春秋” 旁，用不同字体的活字点缀（如篆书 “春”、隶书 “秋”）；</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>互动场景</strong></span>：一位参与者举起印有 “今日宜读书” 的明信片，对着镜头微笑，背景中其他学员正在用活字组合表情包图案（如 “点赞”“爱心”）。</li></ul><h3 style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>四、活动意义</strong></span></h3><ul><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>文化传承</strong></span>：通过 “动手做” 的方式，让抽象的非遗技艺转化为可感知、可参与的具象体验，避免传统工艺沦为 “玻璃柜中的展品”。</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>跨界创新</strong></span>：将活字印刷与现代设计、数字技术结合，证明非遗不是静态的 “老古董”，而是能与当代生活对话的活态文化。</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>情感联结</strong></span>：参与者带走的不仅是一件手工作品，更是对汉字文化的亲近感，以及 “我参与了非遗保护” 的身份认同。</li></ul>', 0, '已结束');
INSERT INTO `activity` VALUES (2, '陶韵千年 —— 传统陶艺沉浸式体验活动', '2025-06-01 09:00:00', '2025-10-10 10:00:00', 'http://localhost:9090/files/download/1747879580407-陶瓷.jpg', '陶瓷是人类最早的人造材料之一，中国陶艺历经万年演变，2010 年 \"景德镇传统陶瓷烧制技艺\" 入选联合国非遗名录。本次活动打破 \"非遗只能远观\" 的壁垒，完整还原 **\"采石制泥 - 揉泥拉坯 - 晾坯修型 - 彩绘上釉 - 入窑烧制\"** 五大核心工序，参与者不仅能亲手制作独一无二的陶器，更能在泥土与指尖的对话中，触摸中华文明的温度。', '<p>一、活动主题​</p><p>\"泥火交融・手作传心 —— 传统陶艺技艺体验之旅\"核心定位：以国家级非遗项目 \"景德镇传统陶瓷烧制技艺\" 为载体，通过 \"古法工序体验 + 现代创意表达\"，让参与者在揉泥、拉坯、上釉、彩绘中感受泥土的生命力，在窑火淬炼中领悟 \"慢工出细活\" 的匠人精神。​</p><p>二、基本信息​</p><p>参与对象​</p><p>核心人群：亲子家庭（6-12 岁儿童需家长陪同）、手工艺爱好者、文旅体验者​</p><p>人数限制：20 组（每组 1-2 人，确保导师一对一指导）​</p><p>报名方式：微信公众号预约（需填写姓名、年龄、联系方式，附 100 字参与初衷）​</p><p>三、活动简介​</p><p>陶瓷是人类最早的人造材料之一，中国陶艺历经万年演变，2010 年 \"景德镇传统陶瓷烧制技艺\" 入选联合国非遗名录。本次活动打破 \"非遗只能远观\" 的壁垒，完整还原 **\"采石制泥 - 揉泥拉坯 - 晾坯修型 - 彩绘上釉 - 入窑烧制\"** 五大核心工序，参与者不仅能亲手制作独一无二的陶器，更能在泥土与指尖的对话中，触摸中华文明的温度。活动亮点：​</p><ol><li>全流程古法体验：使用传统陶轮、手工匣钵、松木燃料（还原古代窑火氛围）；​</li><li>双导师制教学：非遗传承人（负责传统技法）+ 陶瓷设计师（指导创意表达）联合授课；​</li><li>窑变盲盒惊喜：烧制后的作品因窑火变化产生独特釉色，每人收获 \"独一无二的礼物\"。​</li></ol><p>四、活动流程详解​</p><p>【开篇：泥土的文明密码 —— 陶艺历史讲堂】（9:00-10:00）​</p><p> 文物导览：从陶到瓷的千年进化​</p><p>参观工坊内的 \"陶瓷文明长廊\"，重点讲解：​</p><p>旧石器时代红陶（展示半坡遗址陶罐复制品，触摸原始陶纹）；​</p><p>东汉青瓷（对比陶与瓷的本质区别：上釉工艺与高温烧制）；​</p><p>清代珐琅彩瓷（呈现 \"釉上彩\" 与 \"釉下彩\" 的不同表现力）。​</p><p>互动环节：传递真实陶土样本（瓷土、陶土、紫砂泥），让参与者触摸质感差异，猜猜 \"哪种泥土能烧出白瓷\"。​</p><p>2. 技艺解密：非遗传承人的制陶工具箱​</p><p>国家级非遗传承人张师傅（从业 40 年）展示全套传统工具：​</p><p>拉坯工具：陶轮（手动转盘）、木拍（整形）、金属割线（分切坯体）；​</p><p>彩绘工具：鸡头笔（勾线）、扁笔（填色）、吹釉壶（均匀上釉）；​</p><p>窑炉模型：解析 \"镇窑\"（蛋形窑）结构，演示松木燃烧时窑内温度变化（1280-1340℃）。​</p><p>冷知识分享：\"为什么古代陶工要在坯体上刻名字？\"\" 釉料中的矿物颜料如何提炼？\"​</p><p>【实操：从泥土到雏形 —— 拉坯成型工坊】（10:30-12:30）​</p><p>1. 揉泥：唤醒泥土的生命力​</p><p>技法教学：​</p><p>传承人示范 \"菊花揉泥法\"：双手如抱球，顺时针揉压，排出泥料中的气泡（\"揉泥是和泥土对话的第一步，用力要像安抚发脾气的孩子\"）；​</p><p>学员实践：每人领取 500g 景德镇高岭土，在木板上揉制 3 分钟，直至泥团表面光滑如镜。​</p><p>2. 拉坯：让泥土在指尖站立​</p><p>陶轮操作：​</p><p>固定泥团：\"摔泥要稳，像把面团拍在转盘中心，力度均匀才能不偏不倚\"；​</p><p>开孔拉升：拇指垂直戳入泥团，食指抵在外壁，随转盘转动缓慢向上提拉（演示 \"直筒杯\"\" 圆口碗 \" 两种基础器型）；​</p><p>学员尝试：从 \"站稳的泥柱\" 到 \"歪斜的杯子\"，在失败中感受 \"重心控制\" 的重要性，导师逐一纠正手势（如 \"肩膀要下沉，手臂夹紧身体\"）。​</p><p>3. 修坯：赋予器物灵魂的减法​</p><p>坯体阴干 2 小时后，用修坯刀修整底部：​</p><p>\"刀要放平，像切豆腐一样轻轻推进，刻出的圈足要能平稳站立\"；​</p><p>创意延伸：可在坯体表面刻划简单纹饰（如树叶脉络、几何图案），或留下指纹作为 \"独一无二的印记\"。​</p><p>【午休：陶艺主题茶歇】（12:30-13:30）​</p><p>提供陶瓷餐具盛放的茶点：​</p><p>造型：青瓷小碟装绿豆糕（仿宋式茶点）、陶碗盛菊花茶；​</p><p>伴手礼：每人发放《陶艺术语手册》（图文解析 \"生坯\"\" 釉料 \"\"窑变\" 等概念）。​</p><p>【创意：色彩与釉料的魔法 —— 彩绘上釉工坊】（14:00-15:30）​</p><p>1. 釉料实验室：破解色彩密码​</p><p>陶瓷设计师李老师讲解矿物釉料原理：​</p><p>青花料（氧化钴）：\"磨成粉末后调胶，画在坯体上是灰色，烧后变蓝色\"；​</p><p>窑变釉（铜元素）：\"入窑时是无色，高温下与火焰反应，可能变成红色或绿色\"；​</p><p>学员体验：用不同釉料在素坯碎片上涂鸦，放入电窑快速烧制（10 分钟），观察色彩变化的神奇效果。​</p><p>2. 彩绘创作：传统纹样新解​</p><p>经典纹样教学：</p><p>缠枝莲纹（用鸡头笔勾线，讲究 \"线条如铁丝，转折要流畅\"）；​</p><p>冰裂纹（用深色釉料在坯体划裂纹，烧制后形成自然开片）；​</p><p>现代创意：允许用釉料绘制卡通形象、英文单词，或拼贴贝壳、羽毛（经高温会碳化，留下独特肌理）。​</p><p>3. 上釉技法：给陶器穿 \"玻璃衣\"​</p><p>三种传统上釉法任选其一：​</p><p>浸釉（适合小件）：捏住坯体底部，快速浸入釉桶，釉面要均匀无气泡；​</p><p>喷釉（适合复杂造型）：用喷壶距离 20cm 喷洒，形成雾状釉层；​</p><p>荡釉（适合内壁）：倒入釉料后转动坯体，让釉料均匀附着内壁。​</p><p>【期待：窑火淬炼的奇迹 —— 入窑仪式】（15:45-16:15）​</p><p>1. 传统窑炉祭拜​</p><p>传承人主持简易仪式：点燃艾草（驱邪），向窑神碑（仿制古代窑神赵慨像）敬献陶泥坯（象征 \"以泥祭火\"），讲解古人 \"一窑生，一窑死\" 的敬畏之心。​</p><p>2. 现代电窑操作​</p><p>演示电窑控温流程：​</p><p>低温阶段（0-300℃）：排干坯体水分，避免爆裂；​</p><p>高温阶段（1200-1300℃）：釉料熔融，坯体瓷化；​</p><p>冷却阶段（自然降温 8 小时）：防止温差过大导致开裂。​</p><p>学员将作品放入窑内，贴上姓名标签，共同见证 \"封窑时刻\"。​</p><p>【尾声：泥土的重生 —— 作品领取与分享】（活动后 7 日）​</p><p>烧制周期：7-10 天（松木窑需更长时间，电窑可缩短至 48 小时）；​</p><p>领件仪式：​</p><p>收到烧制完成的作品（附 \"窑变证书\"，记录烧制温度、釉色变化原因）；​</p><p>线上分享会：在活动群发布作品照片，票选 \"最具创意奖\"\" 最有温度奖 \"，获奖者获赠陶瓷茶杯；​</p><p>延展服务：提供作品刻字、底座定制等增值服务，让陶器成为可使用、可收藏的纪念品。</p>', 0, '进行中');
INSERT INTO `activity` VALUES (3, '银梭流光 —— 苗族银饰锻造技艺沉浸式体验日', '2025-09-10 09:00:00', '2025-11-30 10:00:00', 'http://localhost:9090/files/download/1747879959987-苗族银饰.jpg', '苗族银饰以 \"以银为纸，以锤为笔\"，2006 年入选首批国家级非遗名录。本次活动聚焦其核心技艺，通过 \"纹样解密 - 锻打实操 - 创意设计\" 全流程体验，让参与者在银片与铁锤的碰撞中，聆听苗族古歌的回响，感受穿戴在身上的 \"无字史书\"。', '<h2>一、活动标题​</h2><p>\"银梭流光 —— 苗族银饰锻造技艺沉浸式体验日\"主题诠释：苗族银饰以 \"以银为纸，以锤为笔\"，2006 年入选首批国家级非遗名录。本次活动聚焦其核心技艺，通过 \"纹样解密 - 锻打实操 - 创意设计\" 全流程体验，让参与者在银片与铁锤的碰撞中，聆听苗族古歌的回响，感受穿戴在身上的 \"无字史书\"。​</p><h2>二、活动简介​</h2><h3>（一）非遗背景​</h3><p>苗族银饰锻造技艺承载着苗族千年迁徙史，银饰纹样涵盖图腾崇拜（龙、凤、蝴蝶妈妈）、自然崇拜（花草、鸟兽）和生活记忆（迁徙路线、耕种场景），一套完整的银饰盛装需经 30 余道工序，耗时数月完成，堪称 \"穿在身上的民族史诗\"。​</p><h3>（二）活动亮点​</h3><ol><li>国家级传承人亲授：跟随苗族银饰锻造技艺国家级传承人龙奶奶（龙彩金，虚构人物）学习锤揲、錾刻、编丝等核心技法；​</li><li>从原料到首饰的蜕变：亲手将 999 纯银条锻打成精致吊坠，体验 \"点银成金\" 的匠人魔法；​</li><li>文化场景沉浸式还原：在吊脚楼布景中聆听银饰叮当韵律，穿戴苗族服饰拍摄 \"银饰盛装照\"，解锁多维度文化体验。​</li></ol><h3>（三）基本信息​</h3><p>主办单位：合肥市市民间文艺家协会​</p><p>参与人数：20 人（16 岁以上，需提前报名，工具材料全含）​</p><h2>三、活动内容详解​</h2><p>【序章：银饰里的千年密码 —— 文化解码课堂】（9:00-10:30）​</p><h4>1. 展厅探秘：行走的银饰博物馆​</h4><p>参观 \"苗族银饰文化展\"，重点解读：​</p><p>图腾纹样：展柜中陈列的 \"蝴蝶妈妈\" 银冠（象征苗族始祖神话）、\"牛首纹\" 项圈（农耕文明印记）；​</p><p>工艺分区：对比錾刻（平面雕花）、累丝（银丝编织）、鎏金（镀金工艺）等技法成品，触摸不同肌理；​</p><p>穿戴礼仪：展示苗族婚礼中的 \"银角盛装\"（重达 5 公斤，需家族女性集体打造），播放台江姊妹节银饰巡游视频。​</p><h4>2. 传承人说：银匠铺的前世今生​</h4><p>龙奶奶现场演示传统工具：​</p><p>锻打工具：2 公斤重的花锤（用于粗锻银条）、0.5 公斤的光锤（平整银面）、刻刀（錾刻细纹）；​</p><p>模具展示：祖传的 \"太阳纹\" 錾刻模具（已有百年历史，边缘布满使用痕迹）、编丝用的 \"蜂窝状\" 铜制拉丝板；​</p><p>故事分享：\"我 12 岁跟着父亲学锻银，第一次打偏了，父亲说 \' 银料可以重熔，但心意不能马虎 \'。\"​</p><h4>3. 互动实验：银饰的 \"加减法\"​</h4><p>发放银片边角料，尝试用砂纸打磨（减法）、用刻刀浅雕（加法），感受银料的延展性，理解 \"千锤百炼\" 的物理意义。​</p><h3>【实操：银砧上的舞蹈 —— 锻造技艺体验】（11:00-13:00）​</h3><h4>1. 化银铸条：从银锭到银片的蜕变​</h4><p>熔银环节：观看匠人用炭火炉熔银（960℃高温下，银块熔成银水，倒入铁模冷却成条）；​</p><p>锻打初体验：每人领取 10cm 长银条，在铁砧上用花锤锻打至 2mm 厚（\"手臂要像钟摆，落点要准，力量要匀\"），感受肌肉记忆的形成。​</p><h4>2. 纹样錾刻：在银片上写诗​</h4><p>经典纹样教学：​</p><p>蕨菜纹（象征祖先迁徙时的食物）：用三角刻刀刻出 \"之\" 字形，模拟蕨菜嫩芽形态；​</p><p>水波纹（纪念长江黄河）：用弧形刻刀划出连续波浪线，龙奶奶示范 \"三刀成浪\" 技法（轻 - 重 - 轻）；​</p><p>创意延伸：允许在银片背面刻写自己的名字或短句（如 \"平安\"\" 长乐 \"），赋予传统纹样现代情感。​</p><h4>3. 塑形抛光：让银饰绽放光彩​</h4><p>弯制成型：用圆铁棒将银片弯成弧形（制作吊坠主体），或用尖嘴钳拧出花丝（制作耳坠流苏）；​</p><p>抛光工序：依次用粗砂、细砂、玛瑙刀打磨，亲眼见证银饰从 \"哑光灰\" 到 \"镜面白\" 的蜕变（\"玛瑙刀要顺着纹理推，就像给银饰做按摩\"）。​</p><h3>【午餐：苗寨长桌宴 —— 银饰与美食的交响】（13:00-14:00）​</h3><p>特色餐食：​</p><p>银饰主题摆盘：酸汤鱼盛放在仿银饰花纹的陶碗中，糯米饭用银制模具压出太阳纹；​</p><p>饮食文化讲解：\"苗族以银饰试毒的说法源于古代，现在更多是吉祥象征，就像这道 \' 银穗玉米粑 \'，寓意五谷丰登。\"​</p><p>伴手礼：每人发放苗族刺绣餐垫（可带走），餐垫纹样与上午学习的蕨菜纹、水波纹呼应。​</p><h3>【创意：当古纹遇见今潮 —— 银饰设计工作坊】（14:30-16:00）​</h3><h4>1. 跨界设计：传统纹样的现代转译​</h4><p>陶瓷设计师阿雅（苗族新生代创作者）分享案例：​</p><p>将 \"蝴蝶妈妈\" 纹样简化为几何图形，设计成项链吊坠；​</p><p>用银片镂空技法制作现代感耳饰，佩戴时投影出苗族古歌歌词；​</p><p>材料升级：提供 925 银链、彩色珐琅釉、天然绿松石，供学员自由搭配。​</p><h4>2. 作品诞生：从图纸到实物​</h4><p>设计草图：在苗族纹样手册上勾选出喜欢的元素（如牛角、铜鼓纹），结合个人风格绘制设计图；​</p><p>组装成型：将錾刻好的银片与银链焊接（使用低温焊枪，导师全程指导），镶嵌宝石或滴珐琅釉（需 24 小时固化，可后续邮寄成品）。​</p><h4>3. 走秀时刻：银饰与服饰的对话​</h4><p>提供苗族传统服饰（银饰盛装、刺绣围裙），学员穿戴自己的作品走秀，龙奶奶用苗语唱诵祝福歌，摄影师抓拍 \"传统与现代碰撞\" 的精彩瞬间。​</p><h3>【尾声：银饰的温度 —— 作品封存与分享】（16:00-16:30）​</h3><h4>1. 匠人认证仪式​</h4><p>龙奶奶为每位学员的作品敲上专属钢印（含活动 LOGO 与日期），颁发 \"银饰工艺体验证书\"；​</p><p>作品装入特制木盒，内衬苗族蜡染布，附手写信：\"每一件银饰都是时光的载体，愿你手中的银，永远闪耀心的温度。\"​</p><h4>2. 文化延续计划​</h4><p>现场开放 \"银饰保养课堂\"：讲解如何用擦银布养护、避免接触化学品；​</p><p>预告后续活动：\"苗族银饰锻造进阶课\"\" 非遗设计师联名展 \"，鼓励持续关注。</p>', 1, '报名中');
INSERT INTO `activity` VALUES (4, '年画里的中国 —— 木版年画沉浸式体验日', '2025-08-10 09:00:00', '2025-08-30 10:00:00', 'http://localhost:9090/files/download/1747880326612-年画.jpg', '木版年画是中国民间艺术的活化石，2006 年入选首批国家级非遗名录。本次活动以 \"刻刀传韵・彩印纳福\" 为核心，完整还原 \"勾稿 - 雕版 - 刷印 - 彩绘\" 四大古法工序，让参与者在墨香与木纹的交织中，解码年画里的吉祥密码，亲手制作承载美好愿景的年画作品，感受传统年俗文化的温暖底色。', '<h2>一、活动标题​</h2><p>\"年画里的中国 —— 木版年画沉浸式体验日\"主题诠释：木版年画是中国民间艺术的活化石，2006 年入选首批国家级非遗名录。本次活动以 \"刻刀传韵・彩印纳福\" 为核心，完整还原 \"勾稿 - 雕版 - 刷印 - 彩绘\" 四大古法工序，让参与者在墨香与木纹的交织中，解码年画里的吉祥密码，亲手制作承载美好愿景的年画作品，感受传统年俗文化的温暖底色。​</p><h2>二、活动简介​</h2><h3>（一）非遗背景​</h3><p>木版年画始于汉代，盛于明清，因 \"贴在门上是门神，贴在墙上是美景，贴在灶上保平安\" 的民俗功能，成为中国人过年的文化符号。苏州桃花坞、天津杨柳青、山东杨家埠等年画流派各具特色，其技艺讲究 \"一稿、二刻、三印、四绘\"，每幅年画需经数十次套印而成，色彩鲜艳热烈，题材涵盖驱邪纳福、五谷丰登、神话传说等，堪称 \"墙上的百科全书\"。​</p><h2>（二）活动亮点​</h2><ol><li>全工序古法体验：使用梨木刻板、矿物颜料、手工宣纸，还原明清时期年画作坊的真实场景；​</li><li>双维度创意融合：既学习传统门神、灶王等经典题材，也尝试用年画技法创作现代插画（如宠物形象、城市地标）；​</li><li>年俗文化活态传承：结合二十四节气讲解年画张贴禁忌，体验 \"扫房贴画\" 的完整年俗流程。​</li></ol><h3>（三）基本信息​</h3><ul><li>主办单位：合肥市非物质文化遗产保护中心​</li><li>承办单位：合肥年画博物馆（国家级非遗传承基地）​</li><li>活动地点：合肥年画博物馆工坊（含雕版陈列室、印刷体验区、彩绘创作间）​</li><li>参与人数：30 人（8 岁以上，亲子家庭需家长陪同，工具材料全含）​</li></ul><h3>三、活动内容详解​</h3><h3>【开篇：年画里的吉祥密码 —— 文化探秘之旅】（9:00-10:30）​</h3><h4>1. 展厅导览：从门神到花笺的千年演变​</h4><p>参观 \"年画的前世今生\" 展厅，重点解读：​</p><p>题材分类：武门神（秦琼、尉迟恭）与文门神（福禄寿三星）的不同寓意；​</p><p>技艺对比：桃花坞年画的 \"粉脸、细眉、红袍\" 细腻风格 vs 杨家埠年画的 \"夸张造型、浓墨重彩\" 民间特色；​</p><p>年俗场景：复原清代民宅年画张贴布局（大门贴门神、灶间贴灶王、卧室贴美人条），播放老艺人讲述 \"年三十贴年画，门神爷守岁\" 的音频。​</p><h4>2. 传承人开课：刻刀下的线条魔法​</h4><p>国家级非遗传承人张师傅（桃花坞年画第 21 代传人）展示镇馆之宝 —— 清代《一团和气》雕版（距今 150 年，木纹中渗透着陈年墨色），讲解：​</p><p>雕版工具：拳刀（刻细线）、弯凿（挖空大面积）、修刀（打磨边缘），演示 \"发刀、挑刀、复刀\" 三步骤；​</p><p>粉本奥秘：古人如何用 \"扑灰法\" 将画稿转移到木板上（现场演示用炭粉拓稿，学员可触摸拓印后的粉本残迹）。​</p><h4>3. 互动实验：色彩里的吉祥符号​</h4><p>发放矿物颜料小样（石绿、朱砂、铅粉），让学员观察天然颜料与化学颜料的区别（\"石绿遇水会分层，这是矿物颗粒的沉淀\"），并尝试调和传统年画的 \"主色 + 辅助色\" 搭配（如红配绿、黄配紫的强烈对比）。​</p><h3>【实操：刻刀与木板的对话 —— 雕版工坊初体验】（11:00-13:00）​</h3><h4>1. 勾稿拓版：把祝福画在木板上​</h4><p>纹样选择：提供传统吉祥纹样（蝙蝠 - 福、鱼 - 余、牡丹 - 富贵）和现代创意模板（生肖卡通、汉字书法），学员用毛笔在薄纸上勾线，反贴到枣木小木板（10cm×15cm）上。​</p><h4>2. 雕版初刻：让线条立起来​</h4><p>技法教学：​</p><p>张师傅示范 \"发刀\"：刀刃与木板呈 30° 角，沿着线条外侧推进，刻出 0.3cm 深的凹槽（\"下刀要稳，像写毛笔字一样讲究提按\"）；​</p><p>学员实践：从简单的直线、弧线开始，逐渐挑战曲线缠绕的蝙蝠纹，感受 \"刻坏一刀，整块木板就报废\" 的匠人压力。​</p><h4>3. 修版打磨：赋予木板呼吸感​</h4><p>用修刀剔除多余木屑，砂纸打磨雕版表面，直至触摸不到毛刺（\"好的雕版，摸起来像婴儿的皮肤，印刷时才不会刮破宣纸\"），部分学员在木板背面刻下自己的名字或日期，留下专属印记。​</p><h3>【午餐：年画主题餐歇 —— 味觉与视觉的年味】（13:00-14:00）​</h3><p>特色饮食：​</p><p>餐盒设计成年画样式，内装 \"福字糕点\"（红枣泥馅，印着蝙蝠纹）、\"年年有余\" 饭团（鱼形模具压制，配海带丝作鱼鳞）；​</p><p>热饮提供木樨茶，杯套印有《老鼠嫁女》年画图案，工作人员讲解 \"喝了木樨茶，来年顶呱呱\" 的民间俗语。​</p><p>文化渗透：餐桌上摆放迷你雕版模型，供学员饭后尝试拓印小图案（如 \"福\"\" 寿 \"）。​</p><h3>【印刷：墨香与宣纸的邂逅 —— 古法刷印工坊】（14:30-16:00）​</h3><h4>1. 调墨备纸：还原传统印刷场景​</h4><p>油墨调制：用陈年松烟墨加白酒、牛皮胶研磨（\"墨要磨得浓而不滞，胶要加得恰到好处，否则会晕染\"），学员戴棉手套体验手工磨墨，感受 \"一锭墨，千次磨\" 的耐心考验。​</p><h4>2. 刷印实操：让图案跃然纸上​</h4><p>传统技法：​</p><p>铺纸：将宣纸对齐雕版，用镇纸固定四角（\"宣纸薄如蝉翼，呼吸太重都会吹皱\"）；​</p><p>趟刷：用鬃刷蘸墨，在雕版上快速打圈，使油墨均匀附着（\"手腕要灵活，像在跳一支纸上的舞蹈\"）；​</p><p>揭纸：捏住纸角轻轻提起，见证黑白线稿从木板转移到纸上的神奇瞬间。​</p><h4>3. 套色印刷：给年画穿上彩衣​</h4><p>复杂年画需 5-8 次套印，本次体验双色套印（主线稿 + 主色调）：​</p><p>先印黑色线稿，晾干 10 分钟；​</p><p>再用红色雕版套印衣饰部分（需严格对齐线稿，否则会 \"重影\"），学员惊叹 \"原来传统年画的鲜艳色彩，是这样一层一层叠出来的\"。​</p><h3>【创意：当年画遇见当代 —— 彩绘与衍生设计】（16:00-17:00）​</h3><h4>1. 古法彩绘：给年画点睛​</h4><p>提供矿物颜料和狼毫笔，学习传统 \"开脸\" 技法（给人物画眼睛、描眉）：​</p><p>\"门神的眼睛要画得圆而有神，这样才能守住家门\"；​</p><p>学员尝试给印刷好的门神画像彩绘，有人给门神加上现代墨镜，有人在背景画上网购快递盒，传统与现代的碰撞引发笑声。​</p><h4>2. 文创衍生：让年画走进生活​</h4><p>提供帆布袋、笔记本、明信片等载体，鼓励将印刷好的年画纹样剪下来，拼贴成现代装饰画；​</p><p>特别体验：用年画雕版在 T 恤上刷印，制作独一无二的 \"国潮\" 服饰（需提前准备无毒水性油墨）。​</p><p>【尾声：年画的温度 —— 作品封藏与分享】（17:00-17:30）​</p><h4>1. 年画装裱仪式​</h4><p>传承人用浆糊将学员作品装裱成轴，贴上活动专属标签（含日期、学员姓名、纹样寓意），讲解 \"年画保存禁忌\"（避免阳光直射、定期用软毛刷除尘）；​</p><p>亲子家庭可将作品带回家，作为当年的 \"门神\" 或 \"墙画\"，体验传统年俗的仪式感。​</p><h4>2. 年俗知识竞赛​</h4><p>抢答问题：\"为什么门神画像要贴一对？\"\" 灶王年画为什么要配麦芽糖？\"，优胜者获赠迷你雕版套装（含小刻刀、木版、宣纸）。​</p><h4>3. 集体合影​</h4><p>在博物馆门前的巨型年画雕塑前合影，每人手持自己的作品，背景播放《恭喜发财》年画主题改编版，传递 \"把吉祥带回家\" 的美好愿景。</p>', 0, '进行中');
INSERT INTO `activity` VALUES (5, '光影传奇 —— 皮影戏沉浸式体验日', '2025-09-10 09:00:00', '2025-11-30 10:00:00', 'http://localhost:9090/files/download/1747880744067-皮影戏.jpg', '皮影戏又称 \"影子戏\"，2011 年入选联合国非遗名录，是集雕刻、绘画、表演、音乐于一体的综合艺术。本次活动以 \"一张牛皮唱尽千古事，两根竹竿舞起百万兵\" 为核心，带领参与者从选皮制皮到雕刻敷彩，从操纵皮影到即兴表演，在光影交织中解锁这项 \"平面木偶戏\" 的千年密码，感受方寸幕布间的乾坤万象。', '<h2>一、活动标题​</h2><p>\"光影传奇 —— 皮影戏沉浸式体验日\"主题诠释：皮影戏又称 \"影子戏\"，2011 年入选联合国非遗名录，是集雕刻、绘画、表演、音乐于一体的综合艺术。本次活动以 \"一张牛皮唱尽千古事，两根竹竿舞起百万兵\" 为核心，带领参与者从选皮制皮到雕刻敷彩，从操纵皮影到即兴表演，在光影交织中解锁这项 \"平面木偶戏\" 的千年密码，感受方寸幕布间的乾坤万象。​</p><h2>二、活动简介​</h2><h3>（一）非遗背景​</h3><p>皮影戏起源于汉代陕西，兴盛于唐宋，鼎盛时期全国有 40 多个流派，以陕西华县皮影的镂空雕刻、甘肃陇东皮影的夸张造型、四川阆中皮影的水路雕花为代表。其制作需经选皮制皮（牛皮 / 驴皮）、雕镂镂空、敷彩缀结等 8 道工序，表演时艺人用三根竹竿操纵皮影，配合弦乐与唱词，演绎历史演义、民间传说，被誉为 \"光影里的戏曲活化石\"。​</p><h3>（二）活动亮点​</h3><ol><li>全产业链体验：从原料处理到舞台表演完整还原，亲手制作可操纵的皮影角色（生 / 旦 / 净 / 末 / 丑）；​</li><li>跨界创意演绎：既能学习传统《西游记》选段，也可自编现代剧情（如 \"皮影版太空漫游\"），用 LED 灯光替代油灯，解锁光影新玩法；​</li><li>多感官沉浸：聆听华县皮影碗碗腔的婉转唱腔，触摸雕刻细腻的皮影皮质，观看幕布上的动态光影魔术。​</li></ol><h3>（三）基本信息​</h3><p>主办单位：合肥市非物质文化遗产保护协会​</p><p>承办单位：合肥 皮影艺术剧院（省级非遗传承基地）​</p><p>活动地点：合肥皮影艺术剧院（含皮影工坊、幕布剧场、非遗展厅）​</p><p>参与人数：25 人（10 岁以上，亲子家庭需家长陪同，工具材料全含）​</p><h2>三、活动内容详解​</h2><h3>【序章：幕布后的千年光影 —— 文化探秘课堂】（9:00-10:30）​</h3><h4>1. 展厅导览：皮影的前世今生​</h4><p>参观 \"皮影的万里长征\" 展厅，重点解读：​</p><p>地域流派：对比陕西皮影的 \"推皮走刀\" 镂空技法（刻制人物须眉）与甘肃皮影的 \"万字纹\" 背景装饰；​</p><p>角色分类：展示 \"生旦\" 的纤巧秀丽（镂空花袖）与 \"净角\" 的粗犷豪放（锯齿纹盔甲），讲解 \"五分头\"\" 七分头 \" 的比例差异；​</p><p>表演场景：复原清代皮影戏台（高 1.8 米，宽 2 米），播放老艺人操纵皮影骑马打斗的珍贵影像，感受 \"一口叙说千古事，双手对舞百万兵\" 的震撼。​</p><h4>2. 传承人开课：牛皮到皮影的蜕变​</h4><p>国家级非遗传承人王师傅（华县皮影第 19 代传人）展示镇馆之宝 —— 清代《封神榜》皮影套组（30 个角色保存完好，牛皮泛着琥珀光泽），讲解：​</p><p>制皮秘方：\"选 4-5 岁秦川黄牛皮，用井水浸泡 7 天，刮去毛肉，晒成透明皮板，这一步叫 \' 刮皮制浆 \'。\"​</p><p>雕刻工具：展示 30 余把不同型号的雕刻刀（斜口刀刻直线、圆口刀挖圆孔、花口刀雕花纹），演示 \"推皮走刀\" 技法（刀刃不动，皮料移动，刻出流畅弧线）。​</p><h4>3. 互动实验：光影魔术初体验​</h4><p>发放半透明油纸和剪纸人物，在台灯下尝试投影：​</p><p>观察 \"近大远小\" 的透视原理，理解皮影表演为何需要离幕布 30cm 最佳距离；​</p><p>尝试用手指做出 \"鸽子\"\" 兔子 \" 的手影，对比皮影雕刻的精细度与手影的抽象性。​</p><h3>【实操：刻刀下的皮影人生 —— 雕刻工坊体验】（11:00-13:00）​</h3><h4>1. 选皮勾稿：赋予牛皮新生命​</h4><p>角色选择：提供传统造型（孙悟空、穆桂英）和现代形象（宇航员、卡通猫）的纸样，学员用铅笔将图案反画到驴皮上（\"皮影是反着雕刻，正着表演，就像照镜子\"）。​</p><h4>2. 雕镂镂空：在牛皮上绣花​</h4><p>技法教学：​</p><p>王师傅示范刻制 \"花旦\" 的头冠：先用斜口刀刻出边缘，再用花口刀在中间雕出梅花纹（\"下刀要稳，力度均匀，否则牛皮会裂\"）；​</p><p>学员实践：从简单的几何纹（圆形、三角形）开始，逐渐挑战人物面部表情（丹凤眼、柳叶眉），感受 \"雕刻三要素\"—— 准（线条精准）、透（镂空均匀）、净（无毛刺）。​</p><h4>3. 敷彩缀结：给皮影穿上戏服​</h4><p>矿物敷彩：使用传统石绿、朱砂、藤黄等矿物颜料，讲解 \"先敷色后镂空\" 的古法（\"红色要涂三遍才够鲜艳，黄色不能和绿色相邻，会串色\"）；​</p><p>组装关节：用细牛皮绳将头、躯干、四肢连接，在背部安装操纵杆（主杆 + 双手杆），见证平面皮料变成立体可动的皮影角色。​</p><h3>【午餐：皮影主题餐歇 —— 舌尖上的非遗】（13:00-14:00）​</h3><h4>特色饮食：​</h4><p>餐盒印着《三国演义》皮影图案，内装 \"皮影造型馒头\"（孙悟空、猪八戒形状）、\"幕布沙拉\"（蔬菜摆成皮影戏台造型）；​</p><p>饮品提供华县皮影戏同款 \"罐罐茶\"，配皮影造型饼干，工作人员讲解 \"边吃边看皮影戏\" 的民间习俗。​</p><p>文化渗透：餐桌上摆放迷你皮影道具，供学员模仿经典动作（如 \"策马扬鞭\"\" 挥剑斩将 \"）。​</p><h3>【表演：幕布前的指尖乾坤 —— 皮影戏工坊】（14:30-16:30）​</h3><h4>1. 操纵技法：让皮影活起来​</h4><p>基础动作教学：​</p><p>单杆操纵（主杆控制头部转动）：\"手腕轻轻摆动，皮影就会点头、摇头\"；​</p><p><br></p><p>双杆操纵（双手杆控制手臂）：\"右手杆向上，左手杆向下，皮影就能挥拳\"；​</p><p>组合动作：学习 \"骑马\"\" 划船 \"\"舞剑\" 等经典动作，配合王师傅的现场伴奏（板胡 + 梆子），感受 \"动作跟着节奏走\" 的表演精髓。​</p><h4>2. 剧本创编：我的皮影故事​</h4><p>传统剧本体验：分组排练《三打白骨精》选段（分配角色：孙悟空、唐僧、白骨精），王师傅指导唱腔（华县皮影碗碗腔：\"音高八度，尾音上扬\"）；​</p><p>现代创意改编：鼓励创作《太空皮影记》，给皮影角色加上火箭、星球等道具，用电子音效替代传统乐器，探索 \"非遗 + 科幻\" 的跨界可能。​</p><h4>3. 光影舞台：幕布后的主角​</h4><p>搭建专业皮影幕布（白色幕布 + LED 背光），学员分组上台表演：​</p><p>传统组：在暖黄色灯光下演绎《西游记》，幕布上皮影的兵器碰撞声与唱腔完美配合；​</p><p>创意组：用彩色灯光打造太空场景，皮影宇航员在幕布上 \"漫步\"，引发观众掌声。​</p><h3>【尾声：光影永存 —— 作品封藏与分享】（17:00-17:30）​</h3><h4>1. 皮影装裱仪式​</h4><p>传承人用红绸布包裹学员制作的皮影角色，装入定制木盒（盒盖刻有 \"光影传奇\" 字样），附手写信：\"每一个皮影都是会讲故事的精灵，愿你手中的光影，永远闪耀创造力的光芒。\"​</p><h4>2. 幕后分享会​</h4><p>学员分享创作心得：\"刻坏了三次才成功的孙悟空头冠，让我明白慢就是快\"；​</p><p>王师傅总结：\"皮影戏的灵魂不在皮影，而在操纵它的人 —— 你们赋予了这些牛皮新的生命。\"​</p><h4>3. 集体合影​</h4><p>在皮影幕布前合影，每人操纵自己的皮影角色摆出经典姿势，背景投影 \"光影传奇\" 主题字，工作人员为每位学员拍摄 \"幕布后的匠人剪影\"，记录专注创作的瞬间。</p>', 1, '报名中');
INSERT INTO `activity` VALUES (6, '丝桐雅韵 —— 古琴斫制与演奏沉浸式体验日', '2025-05-28 08:00:00', '2025-08-10 10:00:00', 'http://localhost:9090/files/download/1747881151804-古琴.jpg', '古琴又称 \"丝桐\"，是中国最古老的弹拨乐器之一，2003 年入选联合国非遗名录。本次活动以 \"一张琴・千年心\" 为核心，带领参与者从选材制形到上漆调音，从识别琴徽到弹奏《沧海一声笑》，在木材与丝弦的共振中，解码 \"琴棋书画\" 之首的文人精神，体验 \"左手按徽、右手拨弦\" 的身心合一之境。', '<h2>一、活动标题​</h2><p>\"丝桐雅韵 —— 古琴斫制与演奏沉浸式体验日\"主题诠释：古琴又称 \"丝桐\"，是中国最古老的弹拨乐器之一，2003 年入选联合国非遗名录。本次活动以 \"一张琴・千年心\" 为核心，带领参与者从选材制形到上漆调音，从识别琴徽到弹奏《沧海一声笑》，在木材与丝弦的共振中，解码 \"琴棋书画\" 之首的文人精神，体验 \"左手按徽、右手拨弦\" 的身心合一之境。​</p><h2>二、活动简介​</h2><h3>（一）非遗背景​</h3><p>古琴有三千多年历史，其斫制技艺（选材、挖槽腹、合琴、上漆）讲究 \"材美工巧\"，琴身弧度、岳山高度均需符合声学原理；演奏技法含 7 种右手指法、13 种左手指法，一曲《广陵散》曾令嵇康慨然赴死，被誉为 \"道器合一\" 的文化象征。​</p><h3>（二）活动亮点​</h3><ol><li>双非遗体验：既学习国家级非遗 \"古琴斫制技艺\"（以扬州琴派为蓝本），又跟随琴家学习减字谱识读与即兴泛音；​</li><li>五感沉浸设计：触摸百年桐木的温润纹理，聆听丝弦振动的空谷之音，嗅闻大漆与朱砂混合的天然气息；​</li><li>身心疗愈结合：在调弦过程中感受 \"中正平和\" 的古琴哲学，配合古琴理疗讲解，解锁传统乐器的现代疗愈价值。​</li></ol><h3>（三）基本信息​</h3><p>主办单位：合肥市古琴研究会​</p><p>承办单位：合肥古琴文化体验馆（国家级非遗传承基地）​</p><p>活动地点：合肥古琴工坊（含斫琴室、琴房、雅集厅）​</p><p>参与人数：15 人（12 岁以上，需提前报名，工具材料全含）​</p><h2>三、活动内容详解​</h2><h3>【序章：丝桐回响 —— 古琴文化解码】（9:00-10:30）​</h3><h4>1. 琴器之美：穿越千年的声音载体​</h4><p>参观 \"古琴形制展\"，重点解读：​</p><p>琴体结构：岳山（琴弦起点）、龙龈（琴弦终点）、十三徽（镶嵌贝壳 / 玉石，标记泛音位置）；</p><p>传世名琴：复制品展示唐代 \"九霄环佩\" 琴（鹿角霜漆胎）、宋代 \"大圣遗音\" 琴（朱砂点徽），触摸不同琴漆的质感差异（糙漆如砂纸，光漆如镜面）；​</p><p>斫琴材料：陈列桐木（面板）、梓木（底板）、鹿角霜（漆胎原料）、丝弦（蚕丝绞制），讲解 \"面桐底梓，阴阳相济\" 的选材哲学。​</p><h4>2. 传承人开课：斫琴师的工具箱​</h4><p>国家级非遗传承人李师傅（扬州琴派第 12 代传人）展示祖传斫琴工具：​</p><p>挖槽工具：弧形刨刀（挖琴腹共鸣腔）、铲刀（修整内壁）、音叉（测试共鸣效果）；​</p><p>上漆工具：牛角刮刀（刮漆胎）、鬃刷（刷大漆）、砂纸（从 80 目到 2000 目，逐级打磨）；​</p><p>故事分享：\"我曾用三年时间斫制一张琴，每天只磨三小时漆，因为 \' 急火攻心，琴音必躁 \'。\"​</p><h4>3. 听觉实验：丝弦与钢弦的对话​</h4><p>对比弹奏丝弦琴（音色温润，余韵悠长）与钢弦琴（音量明亮，适合舞台），让学员闭眼分辨音色差异，理解 \"丝桐合为琴，中有太古声\" 的意境。​</p><h3>【斫琴：木胎上的声学诗篇 —— 斫制工坊体验】（11:00-13:00）​</h3><h4>1. 选材制形：赋予木材音乐灵魂​</h4><p>迷你琴坯制作：每人领取 1:4 比例的桐木琴坯（已开好龙龈岳山），用铅笔在琴面画出弧度线（\"琴额要平，琴腰要收，就像人的肩颈与腰肢\"）。​</p><h4>2. 挖槽调音：给琴腹注入呼吸​</h4><p>共鸣腔处理：​</p><p>用小刨刀轻刨琴腹，李师傅示范 \"前宽后窄\" 的挖制原则（\"前端容指，后端聚音，就像古琴在呼吸\"）；​</p><p>用音叉敲击琴坯，根据回声调整槽腹深度（\"声音闷则浅，声音散则深，好的琴腹能让音波在体内循环\"）。​</p><h4>3. 上漆赋色：给古琴穿衣裳​</h4><p>鹿角霜漆胎：调和鹿角霜与大漆（需戴防毒面具，由师傅提前调制），学员用鬃刷薄刷琴面（\"第一遍漆要稀，像给琴敷面膜，干透后才能刷第二遍\"）；​</p><p>朱砂点徽：用毛笔蘸朱砂漆，在十三徽位置点出直径 2mm 的圆点（\"徽位要准，差之毫厘，泛音必失\"）。​</p><h3>【午餐：琴茶雅集 —— 味觉与听觉的和鸣】（13:00-14:00）​</h3><p>茶歇布置：​</p><p>茶席铺古琴减字谱桌旗，摆放琴形茶盘、埙状茶杯，提供武夷岩茶（象征古琴的 \"金石之音\"）、杏仁酥（雕成琴徽形状）；​</p><p>文化渗透：播放管平湖先生演奏的《流水》，工作人员讲解 \"琴茶同源\" 的文人传统（如陆羽《茶经》与嵇康《琴赋》均追求 \"自然之味\"）。​</p><h3>【操缦：指尖上的山水 —— 古琴演奏工坊】（14:30-16:30）​</h3><h4>1. 减字谱识读：古琴的密码本​</h4><p>琴家张老师讲解减字谱符号：​</p><p>\"⺈\"（勾）：右手无名指勾弦，如 \"勾三弦\" 对应减字谱 \"勹三\"；​</p><p>\"大九\"：左手大指按第九徽，示范 \"按音要实，如人站立于地\"。​</p><h4>2. 指法练习：让丝弦唱出声音​</h4><p>基础指法教学：​</p><p>右手 \"勾、挑、抹\" 三法（配合《仙翁操》单音练习，感受 \"指尖过弦如鱼游水\"）；​</p><p>左手 \"吟、猱、绰、注\" 四韵（在七徽处练习 \"吟音\"，手腕左右摆动，让音波如涟漪扩散）。​</p><h4>3. 曲目演绎：从单音到乐章​</h4><p>传统曲目：集体弹奏《沧海一声笑》（简编版），张老师用琴箫伴奏，讲解 \"宫商角徵羽\" 五声音阶的和谐之美；​</p><p>即兴创作：在琴尾系上彩色丝绦，闭目弹奏单音，用不同力度表现 \"山之巍峨\"（强音）与 \"水之潺湲\"（弱音），探索古琴的即兴表达可能。​</p><h3>【尾声：丝桐成器 —— 作品封藏与雅集】（17:00-17:30）​</h3><h4>1. 古琴落款仪式​</h4><p>李师傅用刻刀在学员琴坯背面刻下姓名与日期（\"落款如盖章，是斫琴师对琴的承诺\"），颁发 \"古琴斫制体验证书\"；​</p><p>琴坯装入棉麻琴囊，附说明书：\"琴漆需阴干三月，期间每月用麂皮擦拭，待完全干透，可配弦成琴。\"​</p><h4>2. 雅集分享会​</h4><p>学员轮流上台，用琴拨敲击自己的琴坯，分享斫制感受：\"挖槽时总怕挖坏，后来明白慢就是对琴的尊重\"；​</p><p>张老师总结：\"古琴之美，美在不完美 —— 每道漆痕、每个徽位，都是人与琴对话的印记。\"​</p><h4>3. 集体合影​</h4><p>在古琴工坊的 \"丝桐林\" 前合影（数十张待髹漆的琴坯立在木架上，阳光透过天窗形成光束），每人手持自己的琴坯与减字谱卷轴，定格 \"人与琴初遇\" 的瞬间。</p>', 0, '已结束');
INSERT INTO `activity` VALUES (7, '针韵绣情 —— 传统刺绣技艺沉浸式体验活动', '2025-08-10 09:00:00', '2025-08-30 10:00:00', 'http://localhost:9090/files/download/1747882254119-刺绣.png', '刺绣是中国民间传统手工艺之一，历史悠久，针法丰富。本次活动旨在让参与者深入了解刺绣文化，亲身体验刺绣技艺的魅力。活动将带领大家从认识刺绣工具和材料开始，学习基础针法，最后完成一件属于自己的刺绣作品。', '<h4 style=\"text-align: start;\">活动标题</h4><p>“针韵绣情 —— 传统刺绣技艺沉浸式体验活动”</p><h4 style=\"text-align: start;\">活动简介</h4><p>刺绣是中国民间传统手工艺之一，历史悠久，针法丰富。本次活动旨在让参与者深入了解刺绣文化，亲身体验刺绣技艺的魅力。活动将带领大家从认识刺绣工具和材料开始，学习基础针法，最后完成一件属于自己的刺绣作品。</p><h4 style=\"text-align: start;\">基本信息</h4><ul><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>主办单位</strong></span>：合肥 市手工艺协会</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>承办单位</strong></span>：合肥刺绣工作室</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>活动地点</strong></span>：合肥刺绣工作室（含展示区、操作区、成品区）</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>参与人数</strong></span>：20 人（10 岁以上，需提前报名，工具材料全含）</li></ul><h4 style=\"text-align: start;\">活动内容</h4><ol><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>刺绣文化导览（9:00 - 10:30）</strong></span></li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>基础针法教学（10:30 - 12:30）</strong></span></li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>午餐与交流（12:30 - 13:30）</strong></span></li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>作品创作（13:30 - 15:30）</strong></span></li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>作品展示与分享（15:30 - 16:00）</strong></span></li></ol><h4 style=\"text-align: start;\">活动意义</h4><ul><li style=\"text-align: start;\">通过亲身体验刺绣技艺，让参与者感受传统文化的魅力，增强对非物质文化遗产的保护意识。</li><li style=\"text-align: start;\">培养参与者的耐心和专注力，提高动手能力和创造力。</li><li style=\"text-align: start;\">促进参与者之间的交流与互动，营造良好的文化氛围。</li></ul>', 0, '进行中');
INSERT INTO `activity` VALUES (8, '刀笔生花 —— 木版水印技艺沉浸式体验日', '2025-09-10 09:00:00', '2025-11-30 10:00:00', 'http://localhost:9090/files/download/1747882682533-刀刻.png', '木版水印是中国传统书画复制的 “魔法”，2006 年入选国家级非遗名录。本次活动以 “一版一刀一世界，一刷一印一乾坤” 为核心，完整还原 “勾稿 - 刻版 - 刷印 - 套色” 四大工序，让参与者在雕版的刀痕与水墨的晕染中，解码 “下真迹一等” 的复制传奇，亲手制作可装裱的水印小品，感受传统技艺对书画艺术的永恒守护。', '<h2 style=\"text-align: start;\">一、活动标题</h2><p><span style=\"font-size: 16px;\"><strong>\"刀笔生花 —— 木版水印技艺沉浸式体验日\"<br>主题诠释</strong></span>：木版水印是中国传统书画复制的 “魔法”，2006 年入选国家级非遗名录。本次活动以 “一版一刀一世界，一刷一印一乾坤” 为核心，完整还原 “勾稿 - 刻版 - 刷印 - 套色” 四大工序，让参与者在雕版的刀痕与水墨的晕染中，解码 “下真迹一等” 的复制传奇，亲手制作可装裱的水印小品，感受传统技艺对书画艺术的永恒守护。</p><h2 style=\"text-align: start;\">二、活动简介</h2><h3 style=\"text-align: start;\">（一）非遗背景</h3><p>木版水印源于唐代，兴盛于明清，尤以明代《十竹斋画谱》、清代《芥子园画传》为代表，其技艺讲究 “三分画七分印”，需按原作笔意雕刻数十块套色版，再逐版刷印，最终实现 “墨韵生动、色彩还原” 的效果。每幅作品需经勾稿（分色）、刻版（木雕）、印刷（手工）三大环节，耗时数月，是中国古代 “工匠精神” 与 “艺术复制” 的巅峰结合。</p><h3 style=\"text-align: start;\">（二）活动亮点</h3><ol><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>全流程技艺揭秘</strong></span>：使用梨木版、松烟墨、雁皮纸，还原明代胡正言 “十竹斋” 的制谱场景，亲眼见证白纸变名画的奇迹；</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>双师制教学模式</strong></span>：书画艺术家（指导勾稿分色）+ 刻版匠人（传授雕版技法）联合授课，兼顾艺术审美与工艺实操；</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>跨界创意延伸</strong></span>：既可复制传统花鸟小品，也可将木版水印用于现代文创（如笔记本封面、丝巾印花），解锁 “老技艺的新活法”。</li></ol><h3 style=\"text-align: start;\">（三）基本信息</h3><ul><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>主办单位</strong></span>：合肥市非物质文化遗产保护中心</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>承办单位</strong></span>：合肥木版水印工坊（国家级非遗传承基地）</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>活动地点</strong></span>：合肥文化创意园 B 座（含古版陈列室、雕版工坊、印刷体验区）</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>参与人数</strong></span>：20 人（12 岁以上，需提前报名，工具材料全含）</li></ul><h2 style=\"text-align: start;\">三、活动内容详解</h2><h3 style=\"text-align: start;\">【序章：水墨的分身术 —— 木版水印文化讲堂】（9:00-10:30）</h3><ol><li style=\"text-align: start;\">古版探秘：从画稿到神还原参观 “水印的前世今生” 展厅，重点解读清代《十竹斋笺谱》原刻版，对比原作与水印复制品，讲解套色印刷原理；巨型流程图解 “勾稿分色→雕版制模→逐版刷印→装裱成画”，突出刻版需按画家笔意、刷印分干湿浓淡的核心难点；陈列勾稿狼毫笔、刻版拳刀、印刷鬃刷等工具，触摸 “拳刀刀刃仅 0.1mm” 的极致工艺。</li><li style=\"text-align: start;\">传承人开课：刀笔下的水墨密码国家级非遗传承人陈师傅以齐白石《虾》为例，演示分色勾稿，保留画家飞白笔触；展示祖传刻版工具包，现场雕刻竹叶纹，强调 “下刀随叶脉走向，轻重要有提按”。</li><li style=\"text-align: start;\">互动实验：色彩的层层叠加用宣纸碎片和三色印泥叠印，理解 “木版水印逐层调色” 的原理（如红 + 黄 = 橙）。</li></ol><h3 style=\"text-align: start;\">【雕版：刀痕里的笔墨精神 —— 刻版工坊体验】（11:00-13:00）</h3><ol><li style=\"text-align: start;\">勾稿分色：给画面拆骨选择传统（梅兰竹菊）或现代（卡通动物）图案，在硫酸纸上勾轮廓、标色区（如 “花瓣 - 粉色版”）。</li><li style=\"text-align: start;\">雕版初刻：让刀痕成为画笔陈师傅示范刻制梅花花瓣，学员从直线（梅枝）练起，逐步挑战曲线，感受 “刻坏一刀即报废” 的匠人压力，领悟 “不完美即手工温度”。</li><li style=\"text-align: start;\">修版打磨：赋予木版呼吸感细砂纸打磨至表面光滑如宣纸，部分学员在版背刻名字或日期，留下专属印记。</li></ol><h3 style=\"text-align: start;\">【午餐：水印主题餐歇 —— 味觉与视觉的墨韵】（13:00-14:00）</h3><ul><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>特色饮食</strong></span>：《芥子园画传》餐盒内有 “墨韵寿司”（竹炭米饭）、“套色饭团”（拼贴花鸟纹），配 “松烟墨茶”（黑芝麻糊）及木版水印书签；</li><li style=\"text-align: start;\"><span style=\"font-size: 16px;\"><strong>文化渗透</strong></span>：餐桌上摆迷你雕版模型，供学员拓印 “福”“寿” 等小图案。</li></ul><h3 style=\"text-align: start;\">【印刷：水墨在纸上的重生 —— 刷印工坊实操】（14:30-16:30）</h3><ol><li style=\"text-align: start;\">调墨备纸：还原古法印刷场景手工研磨松烟墨块，加清水、明胶调制墨汁，体验 “一锭墨，千次磨” 的耐心。</li><li style=\"text-align: start;\">刷印实操：让颜色层层绽放铺雁皮纸、趟刷蘸墨打圈、揭纸显线稿，见证 “画家笔触被复制” 的神奇瞬间。</li><li style=\"text-align: start;\">套色印刷：给画面穿上彩衣双色套印（线稿 + 主色），先印黑色线稿，再套印红色花朵，感受 “严格对齐避免重影” 的精密操作。</li></ol><h3 style=\"text-align: start;\">【创意：当古技遇见当代 —— 水印衍生设计】（16:00-17:00）</h3><ol><li style=\"text-align: start;\">古法装裱：给水印作品点睛简易装裱：浆糊托裱作品至硬卡纸，边缘贴绫布，学员题字落款，赋予个人印记。</li><li style=\"text-align: start;\">文创衍生：让水印走进生活提供帆布袋、笔记本等载体，支持剪印图案拼贴装饰画；用木版在 T 恤刷印 “国潮” 服饰，年轻人印卡通形象。</li></ol><h3 style=\"text-align: start;\">【尾声：刀笔留痕 —— 作品封藏与分享】（17:00-17:30）</h3><ol><li style=\"text-align: start;\">水印装裱仪式作品用红绸布包裹，装入烫印 “刀笔生花” 木盒，附手写信：“刀痕墨色，是与古人的对话。”</li><li style=\"text-align: start;\">幕后分享会学员分享 “不完美边缘更似真花” 的感悟，陈师傅总结：“木版水印的灵魂是机器无法复制的‘人味’。”</li><li style=\"text-align: start;\">集体合影在 “古版墙” 前合影，手持作品与雕版工具，定格 “传统技艺与现代创作者” 同框瞬间。</li></ol>', 1, '报名中');

-- ----------------------------
-- Table structure for admin
-- ----------------------------
DROP TABLE IF EXISTS `admin`;
CREATE TABLE `admin`  (
  `id` int(10) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `username` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '账号',
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '密码',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '姓名',
  `avatar` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '头像',
  `role` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '角色',
  `phone` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '电话',
  `email` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '邮箱',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '管理员' ROW_FORMAT = DYNAMIC;

