-- ----------------------------
-- Table structure for classify
-- ----------------------------
DROP TABLE IF EXISTS `classify`;
CREATE TABLE `classify`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '名称',
  `img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '图片',
  `introduce` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '描述',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '非遗分类' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of classify
-- ----------------------------
INSERT INTO `classify` VALUES (1, '运动项目', 'http://localhost:9090/files/download/1760411161766-1747733340381-7777.jpg', '运动项目类非物质文化遗产将强身健体与文化内涵相结合。太极拳以柔克刚、刚柔并济，动作行云流水，蕴含着阴阳平衡的哲学理念。这类运动不仅能锻炼身体，还能培养人们的专注力与意志力，传承着中华民族的养生智慧与武术文化，展现出独特的东方运动魅力。');
INSERT INTO `classify` VALUES (2, '传统技艺', 'http://localhost:9090/files/download/1760411277051-1747733333947-6666.jpg', '传统技艺是工匠们世代传承的精湛手艺，彰显着独特的匠心与创造力。制茶工艺让茶叶焕发独特风味，云锦织技艺织就华美织物，青瓷烧制技艺塑造出温润瓷器。每一项技艺都蕴含着独特的工艺奥秘与审美追求，它们既是实用的生产技术，也是承载文化底蕴的艺术形式。');
INSERT INTO `classify` VALUES (3, '科技知识', 'http://localhost:9090/files/download/1760411295631-1747733322901-5555.jpg', '科技知识类非物质文化遗产凝聚着古人对自然规律的深刻认知与实践智慧。以二十四节气为例，它根据太阳运行规律划分时节，指导农业生产与日常生活，体现了 “天人合一” 的哲学思想。这些知识不仅是古代科技成就的体现，也为现代社会在生态保护、养生保健等方面提供了宝贵的借鉴。');
INSERT INTO `classify` VALUES (4, '节日仪式', 'http://localhost:9090/files/download/1760411328457-1747733314125-4444.jpg', '节日仪式承载着民族的集体记忆与情感寄托，是传统文化的重要载体。春节阖家团圆、辞旧迎新，端午节纪念屈原、祈求安康，送王船驱邪祈福、祈求平安。这些节日与仪式通过特定的习俗活动，将文化传统融入日常生活，增强民族凝聚力，维系着民族的认同感与归属感。');

