INSERT INTO `heritage` VALUES (2, '中国剪纸', 'http://localhost:9090/files/download/1760412661691-1747730590426-中国剪纸.jpeg', 2, '2025-10-14 11:31:03', '中国剪纸是一种用剪刀或刻刀在纸上剪刻花纹，用于装点生活或配合其他民俗活动的民间艺术。', '<p style=\"text-align: start;\">中国剪纸是一种用剪刀或刻刀在纸上剪刻花纹，用于装点生活或配合其他民俗活动的民间艺术。在中国，剪纸具有广泛的群众基础，交融于各族人民的社会生活，是各种民俗活动的重要组成部分。其传承赓续的视觉形象和造型格式，蕴涵了丰富的文化历史信息，表达了广大民众的社会认知、道德观念、实践经验、生活理想和审美情趣，具有认知、教化、表意、抒情、娱乐、交往等多重社会价值。</p><p style=\"text-align: start;\">2006年5月20日，剪纸艺术遗产经国务院批准列入第一批国家级非物质文化遗产名录。<sup><em> [2]</em></sup>2009年9月28日至10月2日举行的联合国教科文组织保护非物质文化遗产政府间委员会第四次会议上，中国申报的中国剪纸项目入选“人类非物质文化遗产代表作名录”。<sup><em> [3] [19]</em></sup></p><p style=\"text-align: start;\">2018年12月，教育部办公厅关于公布南京航空航天大学为中国剪纸中华优秀传统文化传承基地。</p><h2 style=\"text-align: start;\">历史沿革</h2><h3 style=\"text-align: start;\">先唐</h3><p style=\"text-align: start;\">纸的发明是在公元前的西汉时代，在此之前是不可能有剪纸艺术的出现的，但当时人们运用薄片材料，通过镂空雕刻的技法制成工艺品，却早在未出现纸时就已流行，即以雕、镂、剔、刻、剪的技法在金箔、皮革、绢帛，甚至在树叶上剪刻纹样。《史记》中的剪桐封弟记述了西周初期周成王用梧桐叶剪成“圭”赐其弟，封姬虞到唐为侯。战国时期就有用皮革镂花，（湖北江凌望山一号楚墓出土文物之一），银箔镂空刻花（河南辉县固围村战国遗址出土文物之一），都与剪纸同出一辙，他们的出现都为民间剪纸的形成奠定了一定的基础。<sup><em> [5]</em></sup></p><p style=\"text-align: start;\">南北朝时期《木兰辞》中就有“对镜贴花黄”的诗句。<sup><em> [6]</em></sup>而中国最早的剪纸作品发现<sup><em> [7]</em></sup>，是新疆吐鲁番火焰山附近出土的北朝时期（公元386一581年）五幅团花剪纸。这几幅剪纸，采用重复折叠的方式和形象互不遮挡的处理手法<sup><em> [8]</em></sup>。</p><h3 style=\"text-align: start;\">唐代</h3><p style=\"text-align: start;\">唐代剪纸已处于大发展时期，杜甫《彭衙行》诗中有“暖汤濯我足，翦纸招我魂”的句子，以剪纸招魂的风俗当时就已流传民间。现藏于大英博物馆的唐代剪纸均可看出当时剪纸手工艺术水平已极高，画面构图完整，表达一种天上人间的理想境界。<sup><em> [9]</em></sup>唐代流行颉，其镂花木版纹样具有剪纸特色，如现藏日本正仓院的“对羊”，其羊的纹样就是典型的剪纸手工艺术表现手法。唐代民间还出现了利用剪纸形式制作的漏版印花板，人们用厚纸雕刻成花版，将染料漏印到布匹上，形成美丽的图案。<sup><em> [20]</em></sup>另外，在敦煌莫高窟也出土过唐代及五代的剪纸，如《双鹿塔》《群塔与鹿》《佛塔》等都属于“功德花纸”一类，主要是用来敬供佛像，装饰殿堂、道场。其画面构图复杂，有具体的内容，外还有《菩萨立像》《持幡菩萨立像》等水墨画镂空剪纸，是剪纸与绘画相结合的作品<sup><em> [10]</em></sup>。</p><h3 style=\"text-align: start;\">宋代</h3><p style=\"text-align: start;\">南宋时期，已经出现了以剪纸为职业的行业艺人。据宋人周密《武林旧事》中记载，此时杭州的“小经济”多达上百种。其中就专门有“剪镞花样”者，有的善剪“诸家书字”，有的专剪“诸色花样”<sup><em> [10]</em></sup>。</p><p style=\"text-align: start;\">宋代造纸业成熟，纸品名目繁多，为剪纸的普及提供了条件。如成为民间礼品的“礼花”，贴于窗上的“窗花”，或用于灯彩、茶盏的装饰。<sup><em> [9]</em></sup>宋代民间剪纸的运用范围逐渐扩大，江西吉州窑将剪纸作为陶瓷的花样，通过上釉、烧制使陶瓷更加精美；民间还采用剪纸的形式，用驴、牛、马、羊等动物的皮、雕刻成皮影戏的人物造型；蓝印花布工艺制作的镂花制版是用油纸板雕镂成纹，刮浆印花的花版纹样就是采用剪纸的技法，有阴、阳刻之分，长线要割断，以点分虚实。<sup><em> [20]</em></sup></p><h3 style=\"text-align: start;\">明清</h3><p style=\"text-align: start;\">明、清时期剪纸手工艺术走向成熟，并达到鼎盛时期。民间剪纸手工艺术的运用范围更为广泛，<sup><em> [9]</em></sup>举凡民间灯彩上的花饰，扇面上的纹饰，以及刺绣的花样等等，无一不是利用剪纸作为装饰成再加工的。<sup><em> [21]</em></sup>而更多的是中国民间常常将剪纸作为装饰家居的饰物，美化居家环境，如门栈、窗花、柜花、喜花，棚顶花等都是用来装饰门窗、房间的剪纸。<sup><em> [20]</em></sup></p><p style=\"text-align: start;\">剪纸艺术虽然来自于民间，但到清代已经成为全民性的艺术，就连当时的皇亲国戚也都离不开剪纸。北京故宫的坤宁宫是清代皇帝结婚时的花烛洞房。宫殿前后窗的窗纸都是裱糊在外面的。墙壁用纸裱糊，四角贴有黑色的“囍”字剪纸角花，顶棚中心是黑色的龙凤团花剪纸。宫殿两旁的过道墙壁上也贴有剪纸。从剪纸的纹样、用料、用色来看，与普通农家的顶棚花、墙花相比，除了剪纸图案稍大以外，基本没有差别。</p><h3 style=\"text-align: start;\">近现代</h3><p style=\"text-align: start;\">20世纪初“五四”新文化运动，在先进知识分子蔡元培、鲁迅、刘半农、周作人等倡导下，建立了中国民俗学的雏形。他们广泛收集民间文学资料，同时也努力收集民间美术作品，其中就有民间剪纸这一项。30年代，艺术家陈志农在北京开始了民间剪纸的研究与创作。他用速写和剪影的形式描绘了老北京大量的风俗民情，串街小贩、作坊工匠、食摊茶挑、集市庙会、市井闲人等。</p><p style=\"text-align: start;\">20世纪40年代，以现实生活为题材的剪纸开始出现。1942年，毛泽东发表的《在延安文艺座谈会上的讲话》指出“文艺为工农兵服务”的文艺方针。此后，延安鲁艺的艺术家陈叔亮、张仃、力群、古元、夏风等人开始学习当地具有深厚群众基础的民间剪纸，对民间剪纸进行了搜集、发掘、整理和研究，并创作出了一大批反映边区人民生产、生活、战斗的新剪纸。作品运用了民间传统的样式，描写了抗日战争和边区建设的新内容。它推动了群众性剪纸的创作和发展，使传统的民间剪纸发生了革命性的变化。1944年，在陕甘宁边区还首次展出了西北地区的民间新剪纸作品，为新中国成立后剪纸艺术的发展拉开了序幕。可以说延安的剪纸开创了中国剪纸的新纪元。</p><p style=\"text-align: start;\">新中国成立后，在“百花齐放，推陈出新”文艺方针的指导下，艺术家们创作了大量表现社会主义新人新事的新剪纸，开拓了剪纸创作的道路，也丰富了中国民间装饰美术的形式和内容。在新剪纸的创作中除了表现各行各业新气象的剪纸外，儿童、体育、杂技、歌舞等也成为剪纸最常见的题材。</p><p style=\"text-align: start;\">剪纸艺术自诞生以来，在中国历史上就没有中断过。它充实于各种民俗活动中，是中国民间历史文化内涵最为丰富的艺术形态之一</p>', 10);
INSERT INTO `heritage` VALUES (3, '中国雕版印刷技艺', 'http://localhost:9090/files/download/1760412706312-1747730533662-中国雕版印刷技艺.jpeg', 2, '2025-10-14 11:31:47', '“中国雕版印刷技艺”是传统文化瑰宝，2009年被联合国教科文组织列入人类非物质文化遗产代表作名录。', '<p><span style=\"color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-size: 14px;\">“中国雕版印刷技艺”是传统文化瑰宝，2009年被联合国教科文组织列入人类非物质文化遗产代表作名录。雕版印刷技艺是运用刀具在木板上雕刻文字或图案，再用墨、纸、绢等材料刷印、装订成书籍的一种特殊技艺，迄今已有1300多年的历史，比活字印刷技艺早400多年。它开创了人类复印技术的先河，承载着难以计量的历史文化信息，在世界文化传播史上起着无与伦比的重要作用。</span></p>', 0);
INSERT INTO `heritage` VALUES (4, '中国传统制茶技艺', 'http://localhost:9090/files/download/1760412750664-1747730403443-中国传统制茶技艺.jpeg', 2, '2025-10-14 11:32:51', '制茶也称为茶叶加工，指茶鲜芽叶经过各道制茶工序被加工成各种半成品或成品茶的过程。‌', '<p style=\"text-align: start;\">‌制茶也称为茶叶加工，指茶鲜芽叶经过各道制茶工序被加工成各种半成品或成品茶的过程。‌</p><p style=\"text-align: start;\">制茶涵盖了萎凋、摇青、烘焙等工序，乌龙茶、红茶等是其常见制成品<sup><em> </em></sup>。</p><p style=\"text-align: start;\">北京时间2022年11月29日，中国申报的“中国传统制茶技艺及其相关习俗”，在摩洛哥拉巴特召开的联合国教科文组织保护非物质文化遗产政府间委员会第17届常会上通过评审，列入联合国教科文组织人类非物质文化遗产代表作名录。</p><h2 style=\"text-align: start;\">制茶工艺</h2><p style=\"text-align: start;\">萎凋：使叶质柔软，可塑性大，便于造形。</p><p style=\"text-align: start;\">作青：摇青与堆置交替进行，由摇青与晾青两个过程所组成。作青室温25℃左右为宜，相对湿度80%左右。</p><p style=\"text-align: start;\">摇青：将萎凋的茶叶放在竹筛内，来回揉，使叶片边缘经过摩擦，叶缘细胞受损，经摊置失水，叶中多酚类在酶的作用下，渐渐被氧化，形成茶叶特有的品质。摇青先轻后重，以免梗叶折断造成死青。这样会破坏茶叶的质量。</p><p style=\"text-align: start;\">铁观音宜重摇，延长作青时间；摇青5～6次，使叶缘成朱砂红色，叶中呈黄绿色（半熟香蕉皮）。 摇青过程中，组织因振动而增加细胞吸水力，茎梗的水分往叶脉、叶片输送，香味及可溶性物质输送到叶片，水分由叶片蒸发，摇青后叶子恢复舒张状态，称为「还青」。还青后静置晾青，水分继续蒸发，又呈萎凋状态，经过5～7次摇青、晾青交替进行，叶片呈绿叶红边，状如汤匙状，外观硬挺，手感软，散发出浓郁桂花香，即为作青的适度。</p><p style=\"text-align: start;\">晾青：时间先短后长，摊青先薄后厚。</p><p style=\"text-align: start;\">杀青：是利用高温处理新鲜的茶叶，使之变软，保持绿色，并失去一部分水分，便于揉捻。</p><p style=\"text-align: start;\">温度：280～300℃。</p><p style=\"text-align: start;\">目的：利用高温杀死青叶中的催化酶，使酶失去活性，保持叶片绿色，借热化学反应，消除叶中青臭、苦、涩味，转化为具有花香醇味的杀青叶，能减少茶叶受损情况。</p><p style=\"text-align: start;\">揉捻：茶叶含水量60%为宜，适于整形；提高叶温，揉捻可塑性增强。</p><p style=\"text-align: start;\">闷堆：将锅炒的茶叶，堆积盖布闷黄。</p><p style=\"text-align: start;\">发酵：决定茶叶色、香、味品质的关键。发酵由揉捻开始，因揉捻的压力作用，叶细胞受损，多酚类霉促氧化受损，聚合加速进行，而开始发酵。发酵温度初期32℃～40℃。后期15℃～18℃。发酵初期氧化速度大，要充分供氧，室内宜通风良好。</p><p style=\"text-align: start;\">干燥：</p><p style=\"text-align: start;\">第一阶段：蒸发水分，制止促霉作用，失水快，含水量60%左右降至47%左右，利于除去异杂气味，提高温度，增加通风量。</p><p style=\"text-align: start;\">第二阶段：整形（揉捻），含水量降至18%左右。</p><p style=\"text-align: start;\">第三阶段：足干，含水量5%左右。</p><p style=\"text-align: start;\">干燥温度80℃～130℃左右。</p><h2 style=\"text-align: start;\">制茶过程</h2><p style=\"text-align: start;\">采摘</p><p style=\"text-align: start;\">采摘是用食指与拇指夹住叶间幼梗的中部，借两指的弹力将茶叶摘断，采摘时间以中午十二时至下午三时前较佳，不同的茶采摘部位也不同，有的采一个顶芽和芽旁的第一片叶子叫一心一叶，有的多采一叶叫一心二叶，也有一心三叶。则另有单人式、双人式采茶机，可利用机械采茶，既省力且快速。</p><p style=\"text-align: start;\">日光萎凋</p><p style=\"text-align: start;\">采摘下来之茶须于日光下摊晒，或利用热风使茶菁水分适度蒸散，减少细胞水分含量，降低其活性并除去细胞膜之半透性，而细胞中各化学成分亦得以藉酵素氧化作用引起发酵作用的进行，搅拌后摊平于笳苈上。</p><p style=\"text-align: start;\">炒青</p><p style=\"text-align: start;\">茶菁萎凋至适当程度即以高温炒青破坏叶中酵素活性停止发酵的继续进行，并可除去鲜叶中的臭青味，而鲜叶亦因水分的蒸散而便于揉捻。</p><p style=\"text-align: start;\">揉捻</p><p style=\"text-align: start;\">将炒青后之茶叶置入揉捻机内，使其滚动并形成卷曲状，由于受到揉压，因此遂有部分汁液被挤出而粘附于表面，如此在冲泡时便可很容易地溶解于茶汤之中。不同的茶其揉捻程度也不一样。</p><p style=\"text-align: start;\">团揉</p><p style=\"text-align: start;\">团揉是以布巾包裹茶叶使其成为一圆球状，再以手工或布球揉捻机来回搓压，并不时将茶叶摊开打散以散热，团揉过后的茶叶茶身将更为紧结而形成半球形或球形茶。</p><p style=\"text-align: start;\">渥堆</p><p style=\"text-align: start;\">一般茶青制作到揉捻已算告一段落，剩下的只是干燥，但「后发酵茶」在杀青、揉捻后有一堆放的过程称为「渥堆」，也就是将揉捻过的茶青堆积存放，由于茶青水分颇高，堆放后会发热，且引发了微生物的生长，就因为热度与微生物关系，使茶青产生了另一种的发酵，茶质被「降解」而变得醇和，颜色被氧化而变得深红，这就是所谓的「普洱茶」。</p><p style=\"text-align: start;\">干燥</p><p style=\"text-align: start;\">干燥是利用干燥机以热风烘干揉捻后之茶叶，使其含水量低于百分之四，利于贮藏运销，通常为了能使内外干燥一致，常采用二次干燥法，先使其达到七、八成干燥，然后取出回潮，再进行第二次的干燥。</p><p style=\"text-align: start;\">紧压</p><p style=\"text-align: start;\">紧压就是把制成的茶蒸软后加压成块状，这样茶就被称为「紧压茶」，除便于运输、贮藏外，蒸、压、放的过程中也会为茶塑造出另一种老成、粗犷的风味。</p><p style=\"text-align: start;\">蒸</p><p style=\"text-align: start;\">使茶再多热受潮。</p><p style=\"text-align: start;\">压</p><p style=\"text-align: start;\">利用茶叶本身的胶质使叶子紧密连结在一起，稳定了往后陈放期间受潮、陈化的速度。</p><p style=\"text-align: start;\">放</p><p style=\"text-align: start;\">继续紧压前一些成分的降解与陈化，使茶质变得更醇厚。紧压茶的陈放年份是决定市价很重要的因素，当然陈放的品质也很重要。</p><p style=\"text-align: start;\">紧压的形状有圆饼状、有方砖形、有碗状、有球状、有柱状...等，紧结程度也有所不同，有些紧压茶只要用手一剥就可以剥开，有些紧压茶就非得用工具不可。紧结的程度也会影响陈放的效果，紧结程度高者，陈放的效应慢，茶性显得结实，紧结程度低者，陈放的效应快，茶性显得豪放。</p><h2 style=\"text-align: start;\">制造过程</h2><h3 style=\"text-align: start;\">绿茶</h3><p style=\"text-align: start;\">鲜叶＞杀青＞揉捻＞干燥＞绿茶</p><p style=\"text-align: start;\">杀青方式：1.加热杀青</p><p style=\"text-align: start;\">2.蒸气杀青</p><p style=\"text-align: start;\">干燥方式：</p><p style=\"text-align: start;\">1.炒干（炒青）：长炒青——长条形的炒青绿茶</p><p style=\"text-align: start;\">扁炒青——外形扁平光滑</p><p style=\"text-align: start;\">圆炒青——外形呈圆形颗粒状</p><p style=\"text-align: start;\">特种炒青（细嫩炒青）</p><p style=\"text-align: start;\">2.烘干（烘青）：普通烘青——通常用来熏制花茶</p><p style=\"text-align: start;\">细嫩烘青</p><p style=\"text-align: start;\">3.晒干（晒青）：加工成紧压茶</p><h3 style=\"text-align: start;\">红茶</h3><p style=\"text-align: start;\">鲜叶＞萎凋＞揉捻＞发酵＞干燥＞红茶</p><p style=\"text-align: start;\">发酵：</p><p style=\"text-align: start;\">发酵是制造红茶的关键，又称『渥红』，因叶片中含有生物催化剂『多酚氧化酶』，这种酶在高温下会失去活性，所以红茶不经过杀青，所以酶保持了高度的活性。另外茶叶中含有一类叫做『茶多酚』的无色物质，茶多酚在多酚氧化酶的催化下，很容易氧化，变成红色的化合物，这种化合物一部分溶于水，变成红色的汤，一部分不溶于水，累积在叶片中变成红色，红茶的红汤红叶即如此形成的。</p><p style=\"text-align: start;\">分类：1.小种红茶：红汤红叶，有松烟香，为似桂圆汤。</p><p style=\"text-align: start;\">熏焙：茶叶薄摊于竹筛中，地上堆松材，以明火燃烧，使茶叶吸收大量松烟香味。</p><p style=\"text-align: start;\">2.功夫红茶：发酵至叶色变铜红才能烘干，掌握火温烘至甜香浓郁才是优质产品。（1875年后才有此制法）</p><p style=\"text-align: start;\">3.红碎茶：揉捻时用机器将叶片切碎，成颗粒形碎片。</p><p style=\"text-align: start;\">红茶制法于绿茶之后，约1650年前后才有。</p><h3 style=\"text-align: start;\">青茶</h3><p style=\"text-align: start;\">鲜叶＞晒青＞摇青＞凉青＞杀青＞初揉＞初烘＞包揉＞复烘＞干燥＞青茶（乌龙茶）</p><p style=\"text-align: start;\">属半发酵茶，介于红茶与绿茶之间的茶类。1855年前后才有此种制法。</p><h3 style=\"text-align: start;\">白茶</h3><p style=\"text-align: start;\">鲜叶＞晒干（或用文火烘干）＞白茶</p><p style=\"text-align: start;\">采摘细嫩茶叶，叶背多白茸毛的茶叶，加工时不炒不揉，使白茸毛在茶外表完整的保存下来。</p><p style=\"text-align: start;\">1.银针：又称白毫银针。</p><p style=\"text-align: start;\">2.白牡丹：采摘一芽二叶，萎凋后直接烘干，叶背呈白色，叶面银色，形似牡丹而得名。</p><p style=\"text-align: start;\">3.贡眉：采摘一芽二三叶。</p><p style=\"text-align: start;\">4.寿眉：制造时先经抽针，抽摘出之茶芽做银针，其它叶片制贡眉，制造时使叶缘微卷曲，完整的保留叶背的白茸毛，叶片似老寿星的眉毛而得名。</p><p style=\"text-align: start;\">白茶性凉，具退热降火之功</p><h3 style=\"text-align: start;\">黄茶</h3><p style=\"text-align: start;\">鲜叶＞杀青＞揉捻＞闷堆＞干燥＞黄茶</p><p style=\"text-align: start;\">黄芽茶原料细嫩、采摘单芽或一芽一叶加工而成，主要包括湖南岳阳洞庭湖君山的“君山银针”，四川雅安、名山区的“蒙顶黄芽”和安徽霍山的“霍山黄芽”。</p><h3 style=\"text-align: start;\">黑茶</h3><p style=\"text-align: start;\">鲜叶＞杀青＞初揉＞渥堆＞复揉＞干燥＞黑茶</p><p style=\"text-align: start;\">黑茶由于原料粗老，加之制造过程中一段堆积发酵时间较长，因而叶色多呈暗褐色，故称黑茶。</p><h3 style=\"text-align: start;\">花茶</h3><p style=\"text-align: start;\">将毛茶与花一层层的堆放，经过几个小时，待茶叶吸收了花香之后，将茶叶与花分开，分别烘干之后，再将花朵加到茶叶中即是花茶。以茉莉花为例：50公斤茶叶，大约配15～40公斤的茉莉花。</p><p style=\"text-align: start;\">茶谱中记载，茉莉、玫瑰、蔷薇、蕙兰、莲、桔、栀子、木香、梅花皆可作茶。</p><p style=\"text-align: start;\">注：以上各种茶，因品质特征各有不同，加工方法也千变万化，一般有初加工与精加工之分；初加工的产品一般称为毛茶（或初制茶），将毛茶加工成为精制茶或成品茶。 将各种毛茶或精制茶，用香花熏制后得到的产品称为花茶。毛茶经蒸汽处理，在模中压成各种形状，称为紧压茶。</p>', 0);
INSERT INTO `heritage` VALUES (5, '太极拳', 'http://localhost:9090/files/download/1760412791437-1747729872534-太极拳.jpeg', 1, '2025-10-14 11:33:35', '太极拳，是以中国传统儒、道哲学中的太极、阴阳辩证理念为核心思想，集颐养性情、强身健体、技击对抗等多种功能为一体，结合易学的阴阳五行之变化', '<p style=\"text-align: start;\">中国武术中的拳法、人类非物质文化遗产代表作</p><p style=\"text-align: start;\">太极拳，是以中国传统儒、道哲学中的太极、阴阳辩证理念为核心思想，集颐养性情、强身健体、技击对抗等多种功能为一体，结合易学的阴阳五行之变化，中医经络学，古代的导引术和吐纳术形成的一种内外兼修、柔和、缓慢、轻灵、刚柔相济的中国传统拳术。太极拳主要代表人物有施承志、陈正雷、杨振铎、李秉慈、孙婉容、钟振山等。</p><p style=\"text-align: start;\">1949年后，被国家体委统一改编作为强身健体之体操运动、表演、体育比赛用途。中国改革开放后，部分还原本来面貌；从而再分为比武用的太极拳、体操运动用的太极操和太极推手。</p><p style=\"text-align: start;\">传统太极拳门派众多，常见的太极拳流派有陈氏、杨氏、武氏、吴氏、孙氏、和氏等派别，各派既有传承关系，相互借鉴，也各有自己的特点，呈百花齐放之态。由于太极拳是近代形成的拳种，流派众多，群众基础广泛，因此是中国武术拳种中非常具有生命力的一支。<sup><em> [3]</em></sup></p><p style=\"text-align: start;\">2020年12月，联合国教科文组织保护非物质文化遗产政府间委员会第15届常会将“太极拳”项目列入联合国教科文组织人类非物质文化遗产代表作名录。</p><h3 style=\"text-align: start;\">名称由来</h3><p style=\"text-align: start;\">太极拳属武术一大拳系。太极拳这个名称是因为拳法变幻无穷，遂用中国古代的“阴阳”、“太极”这一哲学理论来解释拳理而被命名的。<sup><em> [6]</em></sup></p><p style=\"text-align: start;\">“太极”一词源出《周易·系辞》：“易有太极，是生两仪。”“太”就是大的意思，“极”就是开始或顶点的意思。宋朝周敦颐在《太极图说》中第一句话就是“无极而太极”，并非说太极从无极产生，而是“太极本无极”之意，意即“太极”是产生万物的本源，含有至高、至极、绝对、唯一之意。太极拳取的也是这个意思。太极图是中国古人的一种最原始的世界观，拳术和太极说的结合，逐步形成了太极拳术。<sup><em> [6]</em></sup></p><p style=\"text-align: start;\">太极拳一词，最早见于署名王宗岳的《太极拳论》。根据文献和口头资料，王宗岳的遗作，是清直隶广平府永年县（今河北省永年县）武澄清（1880年-1884年），在任职河南省舞阳县县令时，得于县属北舞渡镇家盐店，时间约在清咸丰二年（1852年）或稍晚的一段时间里。由于有无王宗岳此人，研究者迄今尚无定论，近十余年来有人还提出《太极拳论》是武禹襄（1812年-1880年）的化名之作。不管上述议论谁是谁非，有一点可以肯定：王宗岳《太极拳论》的原件，谁也没有看到过。<sup><em> [7]</em></sup></p><p style=\"text-align: start;\">武禹襄的长甥李亦畲（1832年-1892年）于光绪七年（1881年）将王宗岳武禹囊的拳论和自身体会，手书三册传世，俗称“老三本”。自藏本封面题名《太极拳论》，下注“后附小序并五字诀”。赠郝和本封面题名《王宗岳太极拳论》，下注“后附小序并五字诀”。这是迄今发现最早的太极拳理论著述。“太极拳”之名、王宗岳和武禹襄的拳论见诸于文字记载的，均首先出于此抄本。<sup><em> [7]</em></sup></p><p style=\"text-align: start;\">1928年定稿的《清史稿》，在《卷五百五・列传二百九十二・艺术四》中记载：“清中叶，河北有太极拳，云其法出自山西王宗岳……至清末，传习者颇众云。”这是太极拳之名见诸官方史书的最早记载。说“河北有太极拳……传习者颇众”，证明永年人杨禄禅、武禹襄所传拳术已正式定名为太极拳了。</p><h3 style=\"text-align: start;\">创始起源</h3><p style=\"text-align: start;\">太极拳究竟为何人所创，又是何时所创，这是一个既不能回避又难以定论的问题，长期困绕着太极拳界。目前，主要有以下6种说法：</p><p style=\"text-align: start;\">1、梁朝的程灵洗</p><p style=\"text-align: start;\">程灵洗，字元涤。南朝梁武帝、元帝年间（502-554）在世。徽州府休宁（今属安徽省）人，亦说陈国新安（今浙江省建德、淳安县一带）人。<sup><em> [21]</em></sup>程灵洗的太极拳由韩拱月所传，韩拱月的老师不得而知。韩拱月传程秘，程秘传程灵洗的太极拳改名小九天，其中提手、穿梭、单鞭、揽雀尾等数势名称与现在的太极拳名称相同，还有几势动作名称与现在的动作名称颇为相似，程所著观经悟会法云：太极拳非纯功于易经不能得。以易经一书，必须朝夕悟在心内，会在身中，超以象外，得其环中，有人所不知而己独知之妙。留有《用功五志》：“博学，是多工夫。审问，不是口问是心问。慎思，听后当留心想之。明辨，生生不已。笃行，如天行健。”《四性归原歌》：“世人不知己之性，何能得知人之性，至于天地亦此性。我赖天地以存身，天地赖我以致局。若能先求知我性，天地授我偏独灵。”</p><p style=\"text-align: start;\">2、唐朝的许宣平</p><p style=\"text-align: start;\">许宣平唐时江南徽洲府歙县人也，受业于于欢子，于欢子的生平不见记藏，许传宋远桥，原有37势动作，但实际上流传下来的却有42势，其中相当动作名称与现在流传的太极举名称相同或近似，练习方法为单势练习，一势练成，再练一势，不分次序，练习者自己选样，至37势逐一练成，动作自然连贯，一气呵成，故又称长拳，留有《八字歌》：“掤、捋、挤、按世界稀，十个艺人十不知，若能轻灵并坚硬，粘黏连随俱无疑，采挒肘靠更出奇，行之不用费心思。果得沾粘连随字，得其环中不支离。”《周身大用歌》：“一要心灵与意静，自然无处不轻灵，二要遍体气流行，定继续不能停，三要喉头永不抛，问尽力下众英豪，如询大用缘何得，表里精粗九不到。”《十六关要诀》:“活泼于腰，灵机于顶，神通于背，流行于气，行之于腿，蹬之于足，运之于掌，通之于指，敛之于髓，达之于神，凝之于耳，息之于鼻，呼吸往来于口，纵之于膝，浑暖于身，全身发之于毛。”《功用歌》:“轻灵活泼求懂劲，阴阳既济无滞病，若得四两拨千斤，开合鼓荡主宰定。”</p><p style=\"text-align: start;\">3.唐朝的李道子</p><p style=\"text-align: start;\">李道子唐朝江南安庆人，尝居武当山南岩宫，所传太极功为先天拳，亦称长拳。先天拳，亦如三十七势，为太极拳别名。宋时传于江南宁国府俞氏，明代传于宋远桥，张松溪等人。所传歌诀：“无声无象，全身空透，应物自然，西山悬磬，虎吼猿鸣，水清河静，翻汇倒海，尽性立命。”</p><p style=\"text-align: start;\">4.唐朝的胡镜子</p><p style=\"text-align: start;\">唐朝的胡镜子传于宋仲殊，宋为安洲人，宋传殷利亨，殷将太极拳名改为后天法，以掤、捋、挤、按、采、挒、肘、靠为主，与太极十三势功用相同。<sup><em> [8]</em></sup></p><p style=\"text-align: start;\">5.张三丰创拳说</p><p style=\"text-align: start;\">历史上有关张三丰的传说最多，争论亦最大，众多人称其为太极拳鼻祖，目前，有据可查的主要是源于明末清初黄宗羲的《王征南基志铭》记载：“少林以拳勇名天下，然主搏于人，人亦得以乘之。有所谓内家拳，以静制动，犯者应手即仆，故别少林为外家，盖起于宋之张三丰。三丰之术，百年之后，流传于陕西，而王宗岳为最著。温州陈洲同从王宗乐受之，以教其乡人，由是流传于温州，嘉靖年间，张松溪为最。”</p><p style=\"text-align: start;\">6.陈王庭创拳说</p><p style=\"text-align: start;\">武术考证家唐豪实地考察了陈家沟，依据陈王庭的遗诗：“叹当年，披坚执锐，扫荡群氛，几次颠险。蒙恩赐，枉徒然，到而今，年老残喘，只落得黄庭一卷随身伴，闲来造拳，忙来时耕田。趁余闲，教下弟子儿孙，成龙成虎任方便。”以上前四种传说有关文字记载主要源于《宋氏家传太极功源流及支流考》手抄本。</p><p style=\"text-align: start;\">关于太极拳起源问题的确有待深人研究，解放以后，大致可以归纳为两类观点：一类认为太极拳是陈王庭所创，发源于陈家沟；一类认为在此之前早有太极拳，大约在南朝韩拱月、程灵洗开始，经唐朝时许宣平、李道子，宋时程必，元时张三丰，明清为王宗岳、蒋发，清中叶陈长兴发展起来。目前，还很难断定太极拳究竟是何人何时创造的，但是可以肯定，太极拳绝非一蹴而就，必然有一个萌生、发展、壮大、成型的过程，是经过数代人的努力形成的，这也正说明了太极拳的源远流长，博大精深。</p>', 6);
INSERT INTO `heritage` VALUES (6, '赛龙舟', 'http://localhost:9090/files/download/1760412886556-wechat_2025-10-14_113415_490.png', 4, '2025-10-14 11:35:06', '赛龙舟，是传统体育、游艺与杂技，流传于湖南省沅陵县、广东省东莞市、贵州省铜仁市、贵州省镇远县等地，国家级非物质文化遗产之一', '<p style=\"text-align: start;\">赛龙舟，是传统体育、游艺与杂技，流传于湖南省沅陵县、广东省东莞市、贵州省铜仁市、贵州省镇远县等地，国家级非物质文化遗产之一。</p><p style=\"text-align: start;\">赛龙舟是中国端午节的习俗之一，也是端午节最重要的节日民俗活动之一，在中国南方地区普遍存在，在北方靠近河湖的城市也有赛龙舟习俗，而大部分是划旱龙舟舞龙船的形式。</p><p style=\"text-align: start;\">关于赛龙舟的起源，有多种说法，有祭曹娥，祭屈原，祭水神或龙神等祭祀活动，其起源可追溯至战国时代。赛龙舟先后传入邻国日本、越南及英国等，是2010年广州亚运会正式比赛项目。</p><p style=\"text-align: start;\">2011年5月23日，赛龙舟经国务院批准列入第三批国家级非物质文化遗产名录。</p><h2 style=\"text-align: start;\">来源传说</h2><ul><li style=\"text-align: start;\">纪念屈原</li></ul><p style=\"text-align: start;\">据《史记》“屈原贾生列传”记载，屈原是战国时期楚怀王的大臣。其倡导举贤授能、富国强兵、联齐抗秦遭到贵族子兰等人强烈反对，屈原遭馋去职，被赶出了都城，流放到沅和湘流域。他在流放了的情况下，写下忧国忧民的《离骚》和《天问》、《九歌》等不朽诗篇。公元前278年，秦军攻破了楚国京都，屈原始终不忍舍弃自己祖国，于五月初五在写下绝笔作《怀沙》之后，抱石投汨罗江身死。</p><p style=\"text-align: start;\">传说屈原死后，楚国百姓哀痛异常，纷纷涌到汨罗江边去凭吊屈原。渔夫们划起船只，在江上来回打捞他的真身。他们争先恐后，追至洞庭湖时不见踪迹。之后每年五月五日划龙舟以纪念之。借划龙舟驱散江中之鱼，以免鱼吃掉屈原的身体。</p><p style=\"text-align: start;\">在湖南汨罗市，竞渡前必先往屈子祠朝庙，将龙头供在祠中神翁祭拜，披红布于龙头上，再安龙头于船上竞渡，既拜龙神，又纪念屈原。而在湖北的屈原家乡秭归，也有祭拜屈原的仪式流传。祭屈原之俗在《隋书·地理志》中有记载：“其迅楫齐驰，棹歌乱响，喧振水陆，观者如云。”唐刘禹锡《竞渡曲》自注：“竞渡始于武陵，及今举楫而相和之，其音咸呼云：‘何在’，斯沼屈之义。”<sup><em> [1]</em></sup></p><ul><li style=\"text-align: start;\">沅陵盘瓠招魂</li></ul><p style=\"text-align: start;\">早在屈原之前，沅陵就有了龙舟。沅陵龙舟发源于远古，祭祀的对象是五溪各族共同的始祖盘瓠。盘瓠曾落户沅陵半溪石穴，生六儿六女，儿女互婚配，繁衍成苗、瑶、侗、土、畲、黎六个民族。盘瓠死后，六族人宴巫请神，为其招魂。因沅陵山多水密，巫师不知他魂落何处，就让各族打造一只龙舟，逐溪逐河寻找呼喊，以至演变成后来的划船招魂的祭巫活动。</p><ul><li style=\"text-align: start;\">纪念曹娥</li></ul><p style=\"text-align: start;\">浙江地区，是以龙舟竞渡纪念曹娥。《后汉书·列女传》中载，曹娥是投江死去的，民间则传说她下江寻找父尸。浙江地区多祭祀之，《点石斋画报·虔祀曹娥》即描绘会稽地区人民祭祀曹娥之景象。兼有纪念当地出生的近代女民主革命家秋瑾的意义。<sup><em> [2]</em></sup></p><ul><li style=\"text-align: start;\">纪念伍子胥</li></ul><p style=\"text-align: start;\">《清嘉录》中记吴地（江苏一带）竞渡，是源于纪念伍子胥，苏州因此有端午祭伍子胥之旧习，并于水上举行竞渡以示纪念。另外还有广西的纪念马援、福州的纪念闽王王审知等仪式。</p><p style=\"text-align: start;\">清乾隆二十九年（1736年），台湾开始举行龙舟竞渡。当时台湾知府蒋元君曾在台南市法华寺半月池主持友谊赛。台湾每年五月五日都举行龙舟竞赛。在香港，也举行竞渡。</p><h2 style=\"text-align: start;\">文化内涵</h2><p style=\"text-align: start;\">“龙舟竞渡”是在战国时代就已有的习俗。战国时期，人们在急鼓声中划刻成龙形的独木舟，做竞渡游戏，以娱神与乐人，此时的龙舟竞渡是祭仪中半宗教性、半娱乐性的节目。在两湖地区，祭屈原与赛龙舟是紧密相关的。可能屈原及曹娥、伍子胥等逝去后，当地人民也曾用魂舟送其灵魂归葬，故有此俗。但赛龙舟除纪念屈原之外，在各地人们还赋予了不同的寓意。</p><p style=\"text-align: start;\">龙船竞渡前，先要请龙、祭神。如广东龙舟，在端午前要从水下起出，祭过在南海神庙中的南海神后，安上龙头、龙尾，再准备竞渡。并且买一对纸制小公鸡置龙船上，认为可保佑船平安。闽、台则往妈祖庙祭拜。有的直接在河边祭龙头，杀鸡滴血于龙头之上，如四川、贵州等个别地区。</p><p style=\"text-align: start;\">赛龙舟前会举行各种祭祀、纪念之仪式，一般都是点香烛，烧纸钱，供以鸡、米、肉、供果、粽子等。如今这些含有迷信色彩朗仪式已很少见，但在过去，人们祭祀龙神庙时气氛很严肃，多祈求农业丰收、风调雨顺、去邪祟、攘灾异、事事如意，也保佑划船平安。用人们的话说，“图个吉利”，表达人们内心良好的愿望。</p>', 0);
INSERT INTO `heritage` VALUES (7, '二十四节气', 'http://localhost:9090/files/download/1760412927892-1747727980617-二十四节气.jpeg', 3, '2025-10-14 11:35:48', '“二十四节气”（24 solar terms）是中国人通过观察太阳周年运动，认知一年中时令、气候、物候等方面变化规律所形成的知识体系和社会实践。是中国传统历法体系及其相关实践活动的重要组成部分，被誉为“中国的第五大发明”。', '<p>中国历法中廿四个特定节令、人类非物质文化遗产代表作</p><p>“二十四节气”（24 solar terms）是中国人通过观察太阳周年运动，认知一年中时令、气候、物候等方面变化规律所形成的知识体系和社会实践。是中国传统历法体系及其相关实践活动的重要组成部分，被誉为“中国的第五大发明”。</p><p>“二十四节气\"起源于黄河流域，是上古农耕文明的产物，春秋时代，制定出仲春、仲夏、仲秋、仲冬等节气。经过不断地改进，到秦汉年间已完全确立二十四节气。公元前104年，汉武帝时期，“二十四节气\"被纳入《太初历》作为指导黄河流域农事的历法补充。<sup><em> [99]</em></sup>二十四节气是以地球绕太阳一周为一年，将地球绕太阳运行一周的轨道分为360°，春分为0°，以后每15°为一个节气，共24个节气。<sup><em> [15]</em></sup>二十四节气划分依据是根据斗转星移，<sup><em> [108]</em></sup>圭表测影，<sup><em> [107]</em></sup>太阳黄经。<sup><em> [106]</em></sup>二十四节气可分为四类，表示寒来暑往变化的有：立春、春分；立夏、夏至；立秋、秋分；立冬、冬至八个节气。象征气温变化的有：小暑、大暑、处暑、小寒、大寒五个节气。反映降水量的有：雨水、谷雨、白露、寒露、霜降、小雪、大雪七个节气。反映物候现象或农事活动的有：惊蛰、清明、小满、芒种四个节气。<sup><em> [14]</em></sup></p><p>2006年5月20日，“二十四节气”作为民俗项目经国务院批准列入第一批国家级非物质文化遗产名录。2016年11月30日，中国“二十四节气”被正式列入联合国教育、科学及文化组织人类非物质文化遗产代表作名录。<sup><em> [74]</em></sup>2017年5月5日，“二十四节气”保护联盟在浙江杭州拱墅区成立。</p><h2>节气渊源</h2><p>“二十四节气\"起源于黄河流域，是上古农耕文明的产物，<sup><em> [99]</em></sup>二十四节气是古人用来指导农事的补充历法，由于其是通过长期观察太阳周年运动，而总结出的一年中时令、气候、物候等方面的变化规律，因此被称为“太阳历”。大约从夏朝开始，劳动人民就遵循二十四节气从事生产活动，所以其又被称为“夏历”。<sup><em> [100]</em></sup>二十四节气可能萌芽于夏商时期，当时由观测日影确定冬至、夏至两个节气。从《夏小正》一书中的有关记载以及殷商时期的甲骨文、遗址发掘中，发现夏商时期应该能够测得冬至、夏至。西周时期，进一步确定春分、秋分两个节气。春秋时期，人们在四时基础上已经能确定八节。《左传》中多处记载了关于八节的信息。《左传·僖公五年》中记载道：“五年春，王正月辛亥朔，日南至。公既视朔，遂登观台以望。而书，礼也。凡分、至、启、闭，必书云物，为备故也。”《左传·昭公十七年》中记载道：“玄鸟氏司分者也，伯赵氏司至者也，青鸟氏司启者也，丹鸟氏司闭者也。”可见春秋时期二十四节气的核心部分一八节已基本确立。战国时期，二十四节气已基本形成。《黄帝内经》《逸周书·时则训》等相关文献均出现有关二十四节气的记载。《黄帝内经》记载道：“五日谓之候，三候谓之气，六气谓之时，四时谓之岁，而各从其主治焉。”《逸周书·时则训》中出现了较为完整的二十四节气排列，顺序内容与现在二十四节气稍有不同。秦汉年间，二十四节气完善定型，二十四节气第一次完整、科学地记载于淮南王刘安主持编著的《淮南子》，并流传至今。<sup><em> [106]</em></sup>汉武帝时期，“二十四节气\"被纳入《太初历》作为指导黄河流域农事的历法补充。现行的“二十四节气”是依据太阳在回归黄道上的位置制定的，即把太阳周年运动轨迹划分为24等份，每15°为1等份，每1等份为一个节气，始于立春，终于大寒。</p><p><br></p><h2>时节交替</h2><p>二十四节气，是中国人通过观察太阳周年运动而形成的时间知识体系。在国际气象界，它被誉为“中国的第五大发明”。<sup><em> [16]</em></sup>二十四节气是以地球绕太阳一周为一年，将地球绕太阳运行一周的轨道分为360°，春分为0°，以后每15°为一个节气，共24个节气。一年12个月，每个月2个节气，上半月为节，后半月为气，简称为节气。“春雨惊春清谷天，夏满芒夏暑相连。秋处露秋寒霜降，冬雪雪冬小大寒。上半年逢六廿一，下半年逢八廿三。每月两节日期定，最多相差一二天。”</p><p><br></p><p><br></p>', 19);

-- ----------------------------
-- Table structure for news
-- ----------------------------
DROP TABLE IF EXISTS `news`;
CREATE TABLE `news`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '资讯标题',
  `introduce` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '资讯简介',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '资讯内容',
  `img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '资讯封面',
  `time` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '发布时间',
  `views` int(11) NULL DEFAULT NULL COMMENT '浏览量',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 14 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '资讯信息' ROW_FORMAT = DYNAMIC;

-- ----------------------------
